{
  "name": "FocoTotal - Adeus Procrastinação",
  "description": "Um assistente pessoal inteligente projetado para ajudar você a vencer a procrastinação com planos de ação personalizados, timer Pomodoro e coaching via IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppView {
  DASHBOARD = 'DASHBOARD',
  PLANNER = 'PLANNER',
  TIMER = 'TIMER',
  COACH = 'COACH'
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
}

export interface ActionPlan {
  title: string;
  steps: string[];
  motivationalQuote: string;
}

export enum ProcrastinationType {
  OVERWHELM = 'Sobrecarregado (Muitas tarefas)',
  PERFECTIONISM = 'Perfeccionismo (Medo de errar)',
  BOREDOM = 'Tédio (Tarefa desinteressante)',
  ANXIETY = 'Ansiedade (Medo do resultado)',
  DISTRACTION = 'Distração (Falta de foco)'
}

import { GoogleGenAI, Chat, GenerateContentResponse, Type } from "@google/genai";
import { ProcrastinationType, ActionPlan } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

const MODEL_NAME = 'gemini-2.5-flash';

export const generateActionPlan = async (task: string, type: ProcrastinationType): Promise<ActionPlan> => {
  if (!apiKey) throw new Error("API Key not found");

  const prompt = `
    O usuário está procrastinando na seguinte tarefa: "${task}".
    O motivo principal identificado é: ${type}.

    Crie um plano de ação curto, prático e motivador para desbloquear o usuário AGORA.
    A resposta deve ser um objeto JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "Um título encorajador para o plano" },
            steps: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "3 a 5 passos pequenos e acionáveis para começar imediatamente" 
            },
            motivationalQuote: { type: Type.STRING, description: "Uma frase curta de impacto para motivar" }
          },
          required: ["title", "steps", "motivationalQuote"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as ActionPlan;
  } catch (error) {
    console.error("Error generating plan:", error);
    throw error;
  }
};

export const createCoachChat = (): Chat => {
  return ai.chats.create({
    model: MODEL_NAME,
    config: {
      systemInstruction: `
        Você é o Coach FocoTotal, um especialista em produtividade empático, firme e prático.
        Seu objetivo é ajudar o usuário a parar de procrastinar e agir.

        Diretrizes:
        1. Respostas curtas e diretas (máximo 3 parágrafos).
        2. Use psicologia comportamental (ex: regra dos 2 minutos, quebrar tarefas).
        3. Seja encorajador, mas não aceite desculpas esfarrapadas.
        4. Fale sempre em Português do Brasil.
      `,
    },
  });
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading = false, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "px-4 py-2 rounded-lg font-medium transition-all duration-200 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 shadow-sm hover:shadow",
    secondary: "bg-white text-slate-700 border border-slate-200 hover:bg-slate-50 hover:border-slate-300",
    danger: "bg-red-50 text-red-600 hover:bg-red-100 border border-red-200",
    ghost: "bg-transparent text-slate-600 hover:bg-slate-100"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <span className="flex items-center gap-2">
          <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processando...
        </span>
      ) : children}
    </button>
  );
};

export default Button;

import React, { useState } from 'react';
import { ProcrastinationType, ActionPlan } from '../types';
import { generateActionPlan } from '../services/geminiService';
import Button from './Button';
import { Brain, CheckCircle, ArrowRight, RefreshCw, AlertCircle } from 'lucide-react';

const Planner: React.FC = () => {
  const [task, setTask] = useState('');
  const [type, setType] = useState<ProcrastinationType>(ProcrastinationType.OVERWHELM);
  const [plan, setPlan] = useState<ActionPlan | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!task.trim()) return;

    setLoading(true);
    setError(null);
    try {
      const result = await generateActionPlan(task, type);
      setPlan(result);
    } catch (err) {
      setError("Não foi possível gerar o plano. Verifique sua conexão ou a chave de API.");
    } finally {
      setLoading(false);
    }
  };

  const reset = () => {
    setPlan(null);
    setTask('');
  };

  if (plan) {
    return (
      <div className="max-w-2xl mx-auto animate-fade-in">
        <div className="bg-white rounded-2xl shadow-xl border border-indigo-50 overflow-hidden">
          <div className="bg-indigo-600 p-6 text-white">
            <h2 className="text-2xl font-bold mb-2">{plan.title}</h2>
            <p className="opacity-90 italic">"{plan.motivationalQuote}"</p>
          </div>

          <div className="p-8">
            <h3 className="text-lg font-semibold text-slate-800 mb-4 flex items-center gap-2">
              <CheckCircle className="w-5 h-5 text-green-500" />
              Seu Plano de Ação Imediata
            </h3>

            <div className="space-y-4">
              {plan.steps.map((step, idx) => (
                <div key={idx} className="flex gap-4 p-4 bg-slate-50 rounded-xl border border-slate-100 hover:border-indigo-200 transition-colors">
                  <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold">
                    {idx + 1}
                  </div>
                  <p className="text-slate-700 font-medium pt-1">{step}</p>
                </div>
              ))}
            </div>

            <div className="mt-8 pt-6 border-t border-slate-100 flex justify-between items-center">
              <p className="text-sm text-slate-500">Comece pelo passo 1 agora mesmo!</p>
              <Button onClick={reset} variant="secondary">
                <RefreshCw className="w-4 h-4 mr-2" />
                Novo Plano
              </Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-xl mx-auto">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-bold text-slate-900 mb-3">Desbloqueio Mental</h2>
        <p className="text-slate-600">Conte-nos o que você está adiando e nós criaremos um micro-plano para você começar.</p>
      </div>

      <div className="bg-white p-8 rounded-2xl shadow-lg border border-slate-200">
        <form onSubmit={handleSubmit} className="space-y-6">

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              O que você precisa fazer?
            </label>
            <input
              type="text"
              value={task}
              onChange={(e) => setTask(e.target.value)}
              placeholder="Ex: Escrever o relatório mensal..."
              className="w-full px-4 py-3 rounded-xl border border-slate-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-2">
              O que você sente sobre isso?
            </label>
            <div className="grid grid-cols-1 gap-3">
              {Object.values(ProcrastinationType).map((t) => (
                <label key={t} className={`flex items-center p-3 rounded-lg border cursor-pointer transition-all ${type === t ? 'border-indigo-500 bg-indigo-50 text-indigo-700' : 'border-slate-200 hover:bg-slate-50'}`}>
                  <input
                    type="radio"
                    name="procType"
                    value={t}
                    checked={type === t}
                    onChange={() => setType(t)}
                    className="w-4 h-4 text-indigo-600 border-gray-300 focus:ring-indigo-500 mr-3"
                  />
                  <span className="text-sm font-medium">{t}</span>
                </label>
              ))}
            </div>
          </div>

          {error && (
            <div className="p-3 bg-red-50 text-red-600 rounded-lg text-sm flex items-center">
              <AlertCircle className="w-4 h-4 mr-2" />
              {error}
            </div>
          )}

          <Button type="submit" className="w-full py-4 text-lg" isLoading={loading}>
            Gerar Plano de Ação <ArrowRight className="ml-2 w-5 h-5" />
          </Button>
        </form>
      </div>
    </div>
  );
};

export default Planner;

import React, { useState, useEffect, useCallback } from 'react';
import Button from './Button';
import { Play, Pause, RotateCcw, Coffee, Zap } from 'lucide-react';

const WORK_TIME = 25 * 60; // 25 minutes
const BREAK_TIME = 5 * 60; // 5 minutes

const Timer: React.FC = () => {
  const [timeLeft, setTimeLeft] = useState(WORK_TIME);
  const [isActive, setIsActive] = useState(false);
  const [mode, setMode] = useState<'work' | 'break'>('work');

  const toggleTimer = useCallback(() => {
    setIsActive(!isActive);
  }, [isActive]);

  const resetTimer = useCallback(() => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? WORK_TIME : BREAK_TIME);
  }, [mode]);

  const switchMode = useCallback((newMode: 'work' | 'break') => {
    setMode(newMode);
    setIsActive(false);
    setTimeLeft(newMode === 'work' ? WORK_TIME : BREAK_TIME);
  }, []);

  useEffect(() => {
    let interval: number | null = null;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((time) => time - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      setIsActive(false);
      // Optional: Play a sound here
      if (mode === 'work') switchMode('break');
      else switchMode('work');
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isActive, timeLeft, mode, switchMode]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const progress = mode === 'work' 
    ? ((WORK_TIME - timeLeft) / WORK_TIME) * 100 
    : ((BREAK_TIME - timeLeft) / BREAK_TIME) * 100;

  return (
    <div className="max-w-md mx-auto text-center">
      <div className="mb-8">
        <h2 className="text-3xl font-bold text-slate-900 mb-2">Método Pomodoro</h2>
        <p className="text-slate-600">25 minutos de foco total, 5 minutos de descanso.</p>
      </div>

      <div className="bg-white rounded-3xl shadow-xl p-8 border border-slate-200 relative overflow-hidden">
        {/* Progress Bar Background */}
        <div 
          className={`absolute bottom-0 left-0 h-2 transition-all duration-1000 ease-linear ${mode === 'work' ? 'bg-indigo-500' : 'bg-green-500'}`}
          style={{ width: `${progress}%` }}
        />

        <div className="flex justify-center gap-4 mb-8">
          <button
            onClick={() => switchMode('work')}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold transition-colors ${
              mode === 'work' 
                ? 'bg-indigo-100 text-indigo-700' 
                : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <Zap className="w-4 h-4" /> Foco
          </button>
          <button
            onClick={() => switchMode('break')}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold transition-colors ${
              mode === 'break' 
                ? 'bg-green-100 text-green-700' 
                : 'text-slate-500 hover:bg-slate-50'
            }`}
          >
            <Coffee className="w-4 h-4" /> Pausa
          </button>
        </div>

        <div className={`text-8xl font-bold tabular-nums mb-8 tracking-tighter ${mode === 'work' ? 'text-slate-800' : 'text-green-600'}`}>
          {formatTime(timeLeft)}
        </div>

        <div className="flex justify-center gap-4">
          <Button 
            onClick={toggleTimer} 
            className={`w-32 py-3 rounded-xl text-lg ${mode === 'break' && isActive ? 'bg-green-600 hover:bg-green-700' : ''}`}
          >
            {isActive ? (
              <>
                <Pause className="w-5 h-5 mr-2" /> Pausar
              </>
            ) : (
              <>
                <Play className="w-5 h-5 mr-2" /> Iniciar
              </>
            )}
          </Button>

          <Button onClick={resetTimer} variant="secondary" className="px-4 py-3 rounded-xl">
            <RotateCcw className="w-5 h-5" />
          </Button>
        </div>

        <p className="mt-6 text-sm text-slate-400">
          {isActive 
            ? (mode === 'work' ? "Mantenha o foco. Você consegue!" : "Relaxe, você mereceu.") 
            : "Pronto para começar?"}
        </p>
      </div>
    </div>
  );
};

export default Timer;

import React, { useState, useRef, useEffect } from 'react';
import { createCoachChat } from '../services/geminiService';
import { ChatMessage } from '../types';
import Button from './Button';
import { Send, User, Sparkles, Bot } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { GenerateContentResponse } from '@google/genai';

const Coach: React.FC = () => {
  // Use a ref to persist the chat session across renders
  const chatSessionRef = useRef(createCoachChat());

  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Olá! Eu sou seu Coach de Produtividade. O que está te impedindo de realizar suas tarefas hoje?'
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      // Create a placeholder for the bot response
      const botMsgId = (Date.now() + 1).toString();
      setMessages(prev => [...prev, { id: botMsgId, role: 'model', text: '' }]);

      const result = await chatSessionRef.current.sendMessageStream({ message: userMsg.text });

      let fullText = '';

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          fullText += c.text;
          setMessages(prev => 
            prev.map(msg => 
              msg.id === botMsgId ? { ...msg, text: fullText } : msg
            )
          );
        }
      }
    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        role: 'model', 
        text: 'Desculpe, tive um problema de conexão. Tente novamente.',
        isError: true 
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto h-[600px] flex flex-col bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-slate-100 bg-indigo-600 text-white flex items-center gap-3">
        <div className="p-2 bg-indigo-500 rounded-lg">
          <Bot className="w-6 h-6" />
        </div>
        <div>
          <h2 className="font-bold">Coach IA</h2>
          <p className="text-indigo-100 text-xs">Sempre disponível para conversar</p>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${
              msg.role === 'user' ? 'bg-slate-200 text-slate-600' : 'bg-indigo-100 text-indigo-600'
            }`}>
              {msg.role === 'user' ? <User className="w-5 h-5" /> : <Sparkles className="w-5 h-5" />}
            </div>

            <div className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm leading-relaxed shadow-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white text-slate-700 border border-slate-100 rounded-tl-none'
            } ${msg.isError ? 'bg-red-50 text-red-600 border-red-200' : ''}`}>
              {msg.role === 'model' ? (
                 <ReactMarkdown 
                    className="prose prose-sm max-w-none prose-p:my-1 prose-headings:my-2 prose-ul:my-1 prose-li:my-0"
                    components={{
                        // Override basic elements to match Tailwind
                        p: ({node, ...props}) => <p className="mb-2 last:mb-0" {...props} />,
                        ul: ({node, ...props}) => <ul className="list-disc ml-4 mb-2" {...props} />,
                        ol: ({node, ...props}) => <ol className="list-decimal ml-4 mb-2" {...props} />,
                    }}
                 >
                    {msg.text}
                 </ReactMarkdown>
              ) : (
                msg.text
              )}
            </div>
          </div>
        ))}
        {isTyping && (
           <div className="flex gap-3">
             <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center">
                <Sparkles className="w-5 h-5 animate-pulse" />
             </div>
             <div className="bg-white px-4 py-3 rounded-2xl rounded-tl-none border border-slate-100 shadow-sm flex items-center gap-1">
               <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce"></span>
               <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-100"></span>
               <span className="w-2 h-2 bg-slate-400 rounded-full animate-bounce delay-200"></span>
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-white border-t border-slate-100">
        <form onSubmit={handleSend} className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Digite aqui... (Ex: Estou sem vontade de começar)"
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
            disabled={isTyping}
          />
          <Button type="submit" disabled={!input.trim() || isTyping} className="rounded-xl px-6">
            <Send className="w-5 h-5" />
          </Button>
        </form>
      </div>
    </div>
  );
};

export default Coach;

import React, { useState } from 'react';
import { AppView } from './types';
import Planner from './components/Planner';
import Timer from './components/Timer';
import Coach from './components/Coach';
import { LayoutDashboard, Timer as TimerIcon, MessageCircle, ArrowRight, BrainCircuit } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);

  const NavButton = ({ view, icon: Icon, label }: { view: AppView, icon: React.ElementType, label: string }) => (
    <button
      onClick={() => setCurrentView(view)}
      className={`flex flex-col items-center justify-center p-3 rounded-xl transition-all duration-200 w-full sm:w-auto ${
        currentView === view
          ? 'bg-indigo-600 text-white shadow-md transform scale-105'
          : 'bg-white text-slate-500 hover:bg-indigo-50 hover:text-indigo-600'
      }`}
    >
      <Icon className="w-6 h-6 mb-1" />
      <span className="text-xs font-medium">{label}</span>
    </button>
  );

  const DashboardCard = ({ 
    title, 
    desc, 
    icon: Icon, 
    colorClass, 
    onClick 
  }: { 
    title: string, 
    desc: string, 
    icon: React.ElementType, 
    colorClass: string,
    onClick: () => void 
  }) => (
    <div 
      onClick={onClick}
      className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 hover:shadow-lg hover:border-indigo-100 transition-all cursor-pointer group"
    >
      <div className={`w-12 h-12 rounded-xl flex items-center justify-center mb-4 ${colorClass}`}>
        <Icon className="w-6 h-6" />
      </div>
      <h3 className="text-lg font-bold text-slate-900 mb-2 group-hover:text-indigo-600 transition-colors">{title}</h3>
      <p className="text-slate-500 text-sm mb-4">{desc}</p>
      <div className="flex items-center text-sm font-semibold text-indigo-600 group-hover:translate-x-1 transition-transform">
        Acessar <ArrowRight className="w-4 h-4 ml-1" />
      </div>
    </div>
  );

  const renderContent = () => {
    switch (currentView) {
      case AppView.PLANNER:
        return <Planner />;
      case AppView.TIMER:
        return <Timer />;
      case AppView.COACH:
        return <Coach />;
      case AppView.DASHBOARD:
      default:
        return (
          <div className="max-w-4xl mx-auto">
            <div className="text-center mb-12">
              <h1 className="text-4xl md:text-5xl font-bold text-slate-900 mb-4 tracking-tight">
                Vença a Procrastinação <br/>
                <span className="text-indigo-600">Agora Mesmo</span>
              </h1>
              <p className="text-lg text-slate-600 max-w-2xl mx-auto">
                Não deixe para amanhã. Use nossas ferramentas inteligentes para recuperar seu foco e produtividade.
              </p>
            </div>

            <div className="grid md:grid-cols-3 gap-6">
              <DashboardCard
                title="Desbloqueio Mental"
                desc="Gere um plano de ação rápido para tarefas que você está evitando."
                icon={BrainCircuit}
                colorClass="bg-purple-100 text-purple-600"
                onClick={() => setCurrentView(AppView.PLANNER)}
