import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading = false, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "px-4 py-2 rounded-lg font-medium transition-all duration-200 flex items-center justify-center disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 shadow-sm hover:shadow dark:bg-indigo-500 dark:hover:bg-indigo-600",
    secondary: "bg-white text-slate-700 border border-slate-200 hover:bg-slate-50 hover:border-slate-300 dark:bg-slate-800 dark:text-slate-200 dark:border-slate-700 dark:hover:bg-slate-750",
    danger: "bg-red-50 text-red-600 hover:bg-red-100 border border-red-200 dark:bg-red-900/20 dark:text-red-400 dark:border-red-800 dark:hover:bg-red-900/30",
    ghost: "bg-transparent text-slate-600 hover:bg-slate-100 dark:text-slate-400 dark:hover:bg-slate-800"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <span className="flex items-center gap-2">
          <svg className="animate-spin h-4 w-4" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          Processando...
        </span>
      ) : children}
    </button>
  );
};

export default Button;

import React, { useState } from 'react';
import { ProcrastinationType, ActionPlan } from '../types';
import { generateActionPlan } from '../services/geminiService';
import Button from './Button';
import { Brain, CheckCircle, ArrowRight, RefreshCw, AlertCircle, Share2, Check, Target } from 'lucide-react';

const Planner: React.FC = () => {
  const [task, setTask] = useState('');
  const [type, setType] = useState<ProcrastinationType>(ProcrastinationType.OVERWHELM);
  const [plan, setPlan] = useState<ActionPlan | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const isTaskValid = task.trim().length >= 3;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const trimmedTask = task.trim();

    if (!trimmedTask) {
      setError("Por favor, descreva a tarefa que você está adiando.");
      return;
    }

    if (trimmedTask.length < 3) {
      setError("A descrição da tarefa é muito curta. Use pelo menos 3 caracteres.");
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const result = await generateActionPlan(trimmedTask, type);
      setPlan(result);
    } catch (err) {
      setError("Não foi possível gerar o plano. Verifique sua conexão ou a chave de API.");
    } finally {
      setLoading(false);
    }
  };

  const handleShare = async () => {
    if (!plan) return;

    const textToCopy = `
🎯 *Plano de Ação: ${plan.title}*
✨ "${plan.motivationalQuote}"

*Passos para agir agora:*
${plan.steps.map((step, i) => `${i + 1}. ${step}`).join('\n')}

_Gerado por FocoTotal - Adeus Procrastinação_
    `.trim();

    try {
      await navigator.clipboard.writeText(textToCopy);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Falha ao copiar:', err);
      alert("Não foi possível copiar automaticamente. Selecione o texto e copie manualmente.");
    }
  };

  const reset = () => {
    setPlan(null);
    setTask('');
    setError(null);
    setCopied(false);
  };

  if (plan) {
    return (
      <div className="max-w-2xl mx-auto animate-fade-in">
