                  <RefreshCw className="w-4 h-4 mr-2" />
                  Novo Plano
                </Button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-bold text-slate-900 dark:text-slate-100 mb-3">Desbloqueio Mental</h2>
