          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-3">
              Qual é a raiz desse bloqueio hoje?
            </label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {Object.values(ProcrastinationType).map((t) => (
                <label 
                  key={t} 
                  className={`flex items-center p-3 rounded-xl border cursor-pointer transition-all duration-200 h-full ${
                    type === t 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 ring-1 ring-indigo-600 dark:bg-indigo-900/20 dark:text-indigo-400 dark:ring-indigo-500' 
                      : 'border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800/50 text-slate-600 dark:text-slate-400'
