import React, { useState, useEffect, useCallback, useRef } from 'react';
import Button from './Button';
import { Play, Pause, RotateCcw, Coffee, Zap, Timer as TimerIcon, Volume2, VolumeX, Bell } from 'lucide-react';

type TimerPreset = 'classic' | 'sprint';

const DURATIONS = {
  classic: { work: 25 * 60, break: 5 * 60 },
  sprint: { work: 50 * 60, break: 10 * 60 },
};

const Timer: React.FC = () => {
  const [preset, setPreset] = useState<TimerPreset>('classic');
  const [mode, setMode] = useState<'work' | 'break'>('work');
  const [timeLeft, setTimeLeft] = useState(DURATIONS.classic.work);
  const [isActive, setIsActive] = useState(false);
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [visualAlert, setVisualAlert] = useState<{ message: string; type: 'work' | 'break' } | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);

  const currentWorkTime = DURATIONS[preset].work;
  const currentBreakTime = DURATIONS[preset].break;

  const playNotificationSound = useCallback((isWorkEnding: boolean) => {
    if (!soundEnabled) return;

    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const ctx = audioContextRef.current;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'sine';
      osc.frequency.setValueAtTime(isWorkEnding ? 440 : 660, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(isWorkEnding ? 220 : 880, ctx.currentTime + 0.5);

      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + 0.1);
      gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.5);

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.start();
      osc.stop(ctx.currentTime + 0.5);
    } catch (e) {
      console.warn("Audio context error", e);
    }
  }, [soundEnabled]);

  const toggleTimer = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    setIsActive(!isActive);
  }, [isActive]);

  const resetTimer = useCallback(() => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? currentWorkTime : currentBreakTime);
    setVisualAlert(null);
  }, [mode, currentWorkTime, currentBreakTime]);

  const switchMode = useCallback((newMode: 'work' | 'break', autoTrigger = false) => {
    setMode(newMode);
    setIsActive(false);
    setTimeLeft(newMode === 'work' ? DURATIONS[preset].work : DURATIONS[preset].break);

    if (autoTrigger) {
      const msg = newMode === 'break' ? 'Trabalho Concluído! Hora de descansar.' : 'Pausa encerrada! De volta ao foco.';
      setVisualAlert({ message: msg, type: newMode });
      playNotificationSound(newMode === 'break');

      setTimeout(() => setVisualAlert(null), 5000);
    }
  }, [preset, playNotificationSound]);

  const changePreset = (newPreset: TimerPreset) => {
    setPreset(newPreset);
    setMode('work');
    setIsActive(false);
    setTimeLeft(DURATIONS[newPreset].work);
    setVisualAlert(null);
  };

  useEffect(() => {
    let interval: number | null = null;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((time) => time - 1);
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      if (mode === 'work') switchMode('break', true);
      else switchMode('work', true);
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isActive, timeLeft, mode, switchMode]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const totalTime = mode === 'work' ? currentWorkTime : currentBreakTime;
  const progress = ((totalTime - timeLeft) / totalTime) * 100;

  return (
    <div className="max-w-md mx-auto text-center relative">
      {visualAlert && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-50 animate-bounce`}>
          <div className={`px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 border-2 ${
            visualAlert.type === 'break' 
              ? 'bg-green-600 border-green-400 text-white dark:bg-green-700' 
              : 'bg-indigo-600 border-indigo-400 text-white dark:bg-indigo-700'
          }`}>
            <Bell className="w-5 h-5 animate-ring" />
            <span className="font-bold">{visualAlert.message}</span>
          </div>
        </div>
      )}

      <div className="mb-8">
        <h2 className="text-3xl font-bold text-slate-900 dark:text-slate-100 mb-2">Timer de Foco</h2>
        <p className="text-slate-600 dark:text-slate-400">Mantenha a disciplina com lembretes inteligentes.</p>
      </div>

      <div className="flex items-center justify-center gap-4 mb-6">
        <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl w-fit">
          <button
            onClick={() => changePreset('classic')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${
              preset === 'classic' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
            }`}
          >
            25/5
          </button>
          <button
            onClick={() => changePreset('sprint')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${
              preset === 'sprint' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
            }`}
          >
            50/10
          </button>
        </div>

        <button
          onClick={() => setSoundEnabled(!soundEnabled)}
          className={`p-2.5 rounded-xl border transition-all ${
            soundEnabled 
              ? 'bg-indigo-50 border-indigo-200 text-indigo-600 dark:bg-indigo-900/30 dark:border-indigo-800 dark:text-indigo-400' 
              : 'bg-slate-50 border-slate-200 text-slate-400 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-600'
          }`}
          title={soundEnabled ? "Desativar som" : "Ativar som"}
        >
          {soundEnabled ? <Volume2 className="w-5 h-5" /> : <VolumeX className="w-5 h-5" />}
        </button>
      </div>

      <div className={`bg-white dark:bg-slate-900 rounded-3xl shadow-xl p-8 border-2 transition-all duration-500 relative overflow-hidden ${
        visualAlert ? 'scale-105 ring-4 ring-indigo-200 dark:ring-indigo-900/40' : ''
      } ${mode === 'work' ? 'border-slate-200 dark:border-slate-800' : 'border-green-100 dark:border-green-900/30'}`}>

        <div 
          className={`absolute bottom-0 left-0 h-2 transition-all duration-1000 ease-linear ${mode === 'work' ? 'bg-indigo-500' : 'bg-green-500'}`}
          style={{ width: `${progress}%` }}
        />

        <div className="flex justify-center gap-4 mb-8">
          <button
            onClick={() => switchMode('work')}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold transition-colors ${
              mode === 'work' 
                ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-400' 
                : 'text-slate-500 dark:text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
            }`}
          >
            <Zap className="w-4 h-4" /> Trabalho
          </button>
          <button
            onClick={() => switchMode('break')}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold transition-colors ${
              mode === 'break' 
                ? 'bg-green-100 dark:bg-green-900/40 text-green-700 dark:text-green-400' 
                : 'text-slate-500 dark:text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
            }`}
          >
            <Coffee className="w-4 h-4" /> Pausa
          </button>
        </div>

        <div className={`text-8xl font-bold tabular-nums mb-8 tracking-tighter transition-colors duration-500 ${mode === 'work' ? 'text-slate-800 dark:text-slate-100' : 'text-green-600 dark:text-green-400'}`}>
          {formatTime(timeLeft)}
        </div>

        <div className="flex justify-center gap-4">
          <Button 
            onClick={toggleTimer} 
            className={`w-32 py-3 rounded-xl text-lg ${mode === 'break' && isActive ? 'bg-green-600 hover:bg-green-700 dark:bg-green-700 dark:hover:bg-green-800' : ''}`}
          >
            {isActive ? (
              <>
                <Pause className="w-5 h-5 mr-2" /> Pausar
              </>
            ) : (
              <>
                <Play className="w-5 h-5 mr-2" /> Iniciar
              </>
            )}
          </Button>

          <Button onClick={resetTimer} variant="secondary" className="px-4 py-3 rounded-xl">
            <RotateCcw className="w-5 h-5" />
          </Button>
        </div>

        <p className="mt-6 text-sm text-slate-400 dark:text-slate-500 min-h-[1.25rem]">
          {isActive 
            ? (mode === 'work' ? "Mantenha o foco. Você consegue!" : "Relaxe, você mereceu.") 
            : visualAlert ? visualAlert.message : "Pronto para começar?"}
        </p>
      </div>

      <div className="mt-8 flex items-center justify-center gap-2 text-slate-400 dark:text-slate-500 text-sm">
        <TimerIcon className="w-4 h-4" />
        <span>Modo atual: <strong>{preset === 'classic' ? 'Clássico' : 'Sprint'}</strong></span>
      </div>
    </div>
  );
};

export default Timer;

import React, { useState, useRef, useEffect } from 'react';
import { createCoachChat } from '../services/geminiService';
import { ChatMessage } from '../types';
import Button from './Button';
import { Send, User, Sparkles, Bot } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { GenerateContentResponse } from '@google/genai';

const Coach: React.FC = () => {
  const chatSessionRef = useRef(createCoachChat());

  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'Olá! Eu sou seu Coach de Produtividade. O que está te impedindo de realizar suas tarefas hoje?'
    }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const botMsgId = (Date.now() + 1).toString();
      setMessages(prev => [...prev, { id: botMsgId, role: 'model', text: '' }]);

      const result = await chatSessionRef.current.sendMessageStream({ message: userMsg.text });

      let fullText = '';

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          fullText += c.text;
          setMessages(prev => 
            prev.map(msg => 
              msg.id === botMsgId ? { ...msg, text: fullText } : msg
            )
          );
        }
      }
    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        role: 'model', 
        text: 'Desculpe, tive um problema de conexão. Tente novamente.',
        isError: true 
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto h-[600px] flex flex-col bg-white dark:bg-slate-900 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors duration-300">
      {/* Header */}
      <div className="p-4 border-b border-slate-100 dark:border-slate-800 bg-indigo-600 dark:bg-indigo-700 text-white flex items-center gap-3">
        <div className="p-2 bg-indigo-500 dark:bg-indigo-600 rounded-lg">
          <Bot className="w-6 h-6" />
        </div>
        <div>
          <h2 className="font-bold">Coach IA</h2>
          <p className="text-indigo-100 text-xs">Sempre disponível para conversar</p>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 dark:bg-slate-950/50 scrollbar-hide">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex gap-3 animate-fade-in ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${
              msg.role === 'user' ? 'bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-400' : 'bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400'
            }`}>
              {msg.role === 'user' ? <User className="w-5 h-5" /> : <Sparkles className="w-5 h-5" />}
            </div>

            <div className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm leading-relaxed shadow-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-300 border border-slate-100 dark:border-slate-800 rounded-tl-none'
            } ${msg.isError ? 'bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 border-red-200 dark:border-red-900' : ''}`}>
              {msg.role === 'model' ? (
                 <ReactMarkdown 
                    className="prose prose-sm max-w-none prose-p:my-1 prose-headings:my-2 prose-ul:my-1 prose-li:my-0 dark:prose-invert"
                    components={{
                        p: ({node, ...props}) => <p className="mb-2 last:mb-0" {...props} />,
                        ul: ({node, ...props}) => <ul className="list-disc ml-4 mb-2" {...props} />,
                        ol: ({node, ...props}) => <ol className="list-decimal ml-4 mb-2" {...props} />,
                    }}
                 >
                    {msg.text}
                 </ReactMarkdown>
              ) : (
                msg.text
              )}
            </div>
          </div>
        ))}
        {isTyping && (
           <div className="flex gap-3">
             <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 flex items-center justify-center">
                <Sparkles className="w-5 h-5 animate-pulse" />
             </div>
             <div className="bg-white dark:bg-slate-900 px-4 py-3 rounded-2xl rounded-tl-none border border-slate-100 dark:border-slate-800 shadow-sm flex items-center gap-1">
               <span className="w-2 h-2 bg-slate-400 dark:bg-slate-600 rounded-full animate-bounce"></span>
               <span className="w-2 h-2 bg-slate-400 dark:bg-slate-600 rounded-full animate-bounce delay-100"></span>
               <span className="w-2 h-2 bg-slate-400 dark:bg-slate-600 rounded-full animate-bounce delay-200"></span>
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="p-4 bg-white dark:bg-slate-900 border-t border-slate-100 dark:border-slate-800 transition-colors">
        <form onSubmit={handleSend} className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="Digite aqui... (Ex: Estou sem vontade de começar)"
            className="flex-1 px-4 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-slate-100 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
            disabled={isTyping}
          />
          <Button type="submit" disabled={!input.trim() || isTyping} className="rounded-xl px-6">
            <Send className="w-5 h-5" />
          </Button>
        </form>
      </div>
    </div>
  );
};

