import React, { useState } from 'react';
import { ProcrastinationType, ActionPlan } from '../types';
import { generateActionPlan } from '../services/geminiService';
import Button from './Button';
import { Brain, CheckCircle, ArrowRight, RefreshCw, AlertCircle, Share2, Check, Target } from 'lucide-react';

const Planner: React.FC = () => {
  const [task, setTask] = useState('');
  const [type, setType] = useState<ProcrastinationType>(ProcrastinationType.OVERWHELM);
  const [plan, setPlan] = useState<ActionPlan | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  const isTaskValid = task.trim().length >= 3;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const trimmedTask = task.trim();

    if (!trimmedTask) {
      setError("Por favor, descreva a tarefa que você está adiando.");
      return;
    }

    if (trimmedTask.length < 3) {
      setError("A descrição da tarefa é muito curta. Use pelo menos 3 caracteres.");
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const result = await generateActionPlan(trimmedTask, type);
      setPlan(result);
    } catch (err) {
      setError("Não foi possível gerar o plano. Verifique sua conexão ou a chave de API.");
    } finally {
      setLoading(false);
    }
  };

  const handleShare = async () => {
    if (!plan) return;

    const textToCopy = `
🎯 *Plano de Ação: ${plan.title}*
✨ "${plan.motivationalQuote}"

*Passos para agir agora:*
${plan.steps.map((step, i) => `${i + 1}. ${step}`).join('\n')}

_Gerado por AntiPro - Adeus Procrastinação_
    `.trim();

    try {
      await navigator.clipboard.writeText(textToCopy);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Falha ao copiar:', err);
      alert("Não foi possível copiar automaticamente. Selecione o texto e copie manualmente.");
    }
  };

  const reset = () => {
    setPlan(null);
    setTask('');
    setError(null);
    setCopied(false);
  };

  if (plan) {
    return (
      <div className="max-w-2xl mx-auto animate-fade-in">
        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-xl border border-indigo-50 dark:border-slate-800 overflow-hidden">
          <div className="bg-indigo-600 dark:bg-indigo-700 p-6 text-white">
            <div className="flex items-center gap-3 mb-2">
              <Target className="w-8 h-8 text-indigo-200" />
              <h2 className="text-2xl font-bold">{plan.title}</h2>
            </div>
            <p className="opacity-90 italic ml-11">"{plan.motivationalQuote}"</p>
          </div>

          <div className="p-8">
            <h3 className="text-lg font-semibold text-slate-800 dark:text-slate-100 mb-4 flex items-center gap-2">
              <CheckCircle className="w-5 h-5 text-green-500" />
              Seu Plano de Ação Imediata
            </h3>

            <div className="space-y-4">
              {plan.steps.map((step, idx) => (
                <div key={idx} className="flex gap-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800 hover:border-indigo-200 dark:hover:border-indigo-900/50 transition-colors">
                  <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 flex items-center justify-center font-bold">
                    {idx + 1}
                  </div>
                  <p className="text-slate-700 dark:text-slate-300 font-medium pt-1">{step}</p>
                </div>
              ))}
            </div>

            <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 flex flex-wrap gap-4 justify-between items-center">
              <p className="text-sm text-slate-500 dark:text-slate-400 flex-1 min-w-[200px]">Comece pelo passo 1 agora mesmo!</p>
              <div className="flex gap-2 w-full sm:w-auto">
                <Button 
                  onClick={handleShare} 
                  variant="secondary" 
                  className={`flex-1 sm:flex-none transition-all ${copied ? 'border-green-500 text-green-600 bg-green-50 dark:bg-green-900/20 dark:text-green-400 dark:border-green-800' : ''}`}
                >
                  {copied ? (
                    <>
                      <Check className="w-4 h-4 mr-2" />
                      Copiado!
                    </>
                  ) : (
                    <>
                      <Share2 className="w-4 h-4 mr-2" />
                      Compartilhar
                    </>
                  )}
                </Button>
                <Button onClick={reset} variant="secondary" className="flex-1 sm:flex-none">
                  <RefreshCw className="w-4 h-4 mr-2" />
                  Novo Plano
                </Button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-bold text-slate-900 dark:text-slate-100 mb-3">Desbloqueio Mental</h2>
        <p className="text-slate-600 dark:text-slate-400">Identifique seu bloqueio para um plano de ação personalizado.</p>
      </div>

      <div className="bg-white dark:bg-slate-900 p-8 rounded-2xl shadow-lg border border-slate-200 dark:border-slate-800 transition-colors duration-300">
        <form onSubmit={handleSubmit} className="space-y-6">

          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
              O que você precisa fazer?
            </label>
            <input
              type="text"
              value={task}
              onChange={(e) => {
                setTask(e.target.value);
                if (error) setError(null);
              }}
              placeholder="Ex: Começar a estudar para a prova..."
              className={`w-full px-4 py-3 rounded-xl border focus:ring-2 outline-none transition-all dark:bg-slate-800 dark:text-slate-100 ${
                error && !task.trim() 
                  ? 'border-red-300 focus:ring-red-500 bg-red-50 dark:border-red-900 dark:bg-red-900/10' 
                  : 'border-slate-300 dark:border-slate-700 focus:ring-indigo-500 focus:border-indigo-500'
              }`}
              required
            />
            {error && (
              <p className="mt-2 text-sm text-red-600 dark:text-red-400 flex items-center gap-1 animate-pulse">
                <AlertCircle className="w-4 h-4" /> {error}
              </p>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-3">
              Qual é a raiz desse bloqueio hoje?
            </label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {Object.values(ProcrastinationType).map((t) => (
                <label 
                  key={t} 
                  className={`flex items-center p-3 rounded-xl border cursor-pointer transition-all duration-200 h-full ${
                    type === t 
                      ? 'border-indigo-600 bg-indigo-50 text-indigo-700 ring-1 ring-indigo-600 dark:bg-indigo-900/20 dark:text-indigo-400 dark:ring-indigo-500' 
                      : 'border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800/50 text-slate-600 dark:text-slate-400'
                  }`}
                >
                  <input
                    type="radio"
                    name="procType"
                    value={t}
                    checked={type === t}
                    onChange={() => setType(t)}
                    className="w-4 h-4 text-indigo-600 border-gray-300 focus:ring-indigo-500 mr-3"
                  />
                  <span className="text-xs font-semibold leading-tight">{t}</span>
                </label>
              ))}
            </div>
          </div>

          <Button 
            type="submit" 
            className="w-full py-4 text-lg" 
            isLoading={loading}
            disabled={!isTaskValid && task.length > 0}
          >
            Gerar Meu Plano de Ação <ArrowRight className="ml-2 w-5 h-5" />
          </Button>

          {!isTaskValid && task.length > 0 && task.length < 3 && (
            <p className="text-center text-xs text-slate-400 dark:text-slate-500">Descreva sua tarefa um pouco mais...</p>
          )}
        </form>
      </div>
    </div>
  );
};

export default Planner;

import React, { useState, useRef, useEffect } from 'react';
import { createCoachChat } from '../services/geminiService';
import { ChatMessage } from '../types';
import Button from './Button';
import { Send, User, Sparkles, Bot } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { GenerateContentResponse } from '@google/genai';

const Coach: React.FC = () => {
  const chatSessionRef = useRef(createCoachChat());

  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    const greetings = [
      'Olá! Eu sou seu Coach de Produtividade. O que está te impedindo de realizar suas tarefas hoje?',
      'Bem-vindo ao AntiPro. Estou pronto para te ajudar a sair da inércia. O que você está adiando no momento?',
      'Oi! Vamos transformar essa procrastinação em ação? Me conte qual tarefa está pesando na sua lista agora.'
    ];
    const randomGreeting = greetings[Math.floor(Math.random() * greetings.length)];
    return [
      {
        id: 'welcome',
        role: 'model',
        text: randomGreeting
      }
    ];
  });

  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const botMsgId = (Date.now() + 1).toString();
      setMessages(prev => [...prev, { id: botMsgId, role: 'model', text: '' }]);

      const result = await chatSessionRef.current.sendMessageStream({ message: userMsg.text });

      let fullText = '';

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          fullText += c.text;
          setMessages(prev => 
            prev.map(msg => 
              msg.id === botMsgId ? { ...msg, text: fullText } : msg
            )
          );
        }
      }
    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, { 
        id: Date.now().toString(), 
        role: 'model', 
        text: 'Desculpe, tive um problema de conexão. Tente novamente.',
        isError: true 
      }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto h-[600px] flex flex-col bg-white dark:bg-slate-900 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors duration-300">
      {/* Header */}
      <div className="p-4 border-b border-slate-100 dark:border-slate-800 bg-indigo-600 dark:bg-indigo-700 text-white flex items-center gap-3">
        <div className="p-2 bg-indigo-500 dark:bg-indigo-600 rounded-lg">
          <Bot className="w-6 h-6" />
        </div>
        <div>
          <h2 className="font-bold">Coach IA</h2>
          <p className="text-indigo-100 text-xs">Sempre disponível para conversar</p>
        </div>
      </div>

      {/* Messages */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50 dark:bg-slate-950/50 scrollbar-hide">
        {messages.map((msg) => (
          <div
            key={msg.id}
            className={`flex gap-3 animate-fade-in ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
          >
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${
              msg.role === 'user' ? 'bg-slate-200 dark:bg-slate-800 text-slate-600 dark:text-slate-400' : 'bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400'
            }`}>
              {msg.role === 'user' ? <User className="w-5 h-5" /> : <Sparkles className="w-5 h-5" />}
            </div>

            <div className={`max-w-[80%] rounded-2xl px-4 py-3 text-sm leading-relaxed shadow-sm ${
              msg.role === 'user' 
                ? 'bg-indigo-600 text-white rounded-tr-none' 
                : 'bg-white dark:bg-slate-900 text-slate-700 dark:text-slate-300 border border-slate-100 dark:border-slate-800 rounded-tl-none'
            } ${msg.isError ? 'bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 border-red-200 dark:border-red-900' : ''}`}>
              {msg.role === 'model' ? (
                 <ReactMarkdown 
                    className="prose prose-sm max-w-none prose-p:my-1 prose-headings:my-2 prose-ul:my-1 prose-li:my-0 dark:prose-invert"
                    components={{
                        p: ({node, ...props}) => <p className="mb-2 last:mb-0" {...props} />,
                        ul: ({node, ...props}) => <ul className="list-disc ml-4 mb-2" {...props} />,
                        ol: ({node, ...props}) => <ol className="list-decimal ml-4 mb-2" {...props} />,
                    }}
                 >
                    {msg.text}
                 </ReactMarkdown>
              ) : (
                msg.text
              )}
            </div>
          </div>
        ))}
        {isTyping && (
           <div className="flex gap-3">
             <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 flex items-center justify-center">
                <Sparkles className="w-5 h-5 animate-pulse" />
