import React, { useState, useEffect } from 'react';
import { AppView, User } from './types';
import Planner from './components/Planner';
import Timer from './components/Timer';
import Coach from './components/Coach';
import LandingPage from './components/LandingPage';
import Button from './components/Button';
import { LayoutDashboard, Timer as TimerIcon, MessageCircle, ArrowRight, BrainCircuit, Moon, Sun, Lock, LogOut } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [user, setUser] = useState<User | null>(null);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('theme');
      return saved === 'dark' || (!saved && window.matchMedia('(prefers-color-scheme: dark)').matches);
    }
    return false;
  });

  // Load user from storage
  useEffect(() => {
    const savedUser = localStorage.getItem('antipro_user');
    if (savedUser) {
      setUser(JSON.parse(savedUser));
    }
  }, []);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const handleRegister = (userData: { name: string; email: string; phone: string }) => {
    const newUser: User = {
      ...userData,
      createdAt: Date.now(),
      isSubscribed: false
    };
    setUser(newUser);
    localStorage.setItem('antipro_user', JSON.stringify(newUser));
    setCurrentView(AppView.DASHBOARD);
  };

  const handleLogout = () => {
    localStorage.removeItem('antipro_user');
    setUser(null);
    setCurrentView(AppView.DASHBOARD);
  };

  const handleSubscribe = () => {
    if (user) {
      const updatedUser = { ...user, isSubscribed: true };
      setUser(updatedUser);
      localStorage.setItem('antipro_user', JSON.stringify(updatedUser));
      setCurrentView(AppView.DASHBOARD);
    }
  };

  // Logic to check if trial is expired
  const isTrialExpired = () => {
    if (!user) return false;
    if (user.isSubscribed) return false;

    const threeDaysInMs = 3 * 24 * 60 * 60 * 1000;
    return (Date.now() - user.createdAt) > threeDaysInMs;
  };

  const trialDaysLeft = () => {
    if (!user) return 0;
    const threeDaysInMs = 3 * 24 * 60 * 60 * 1000;
    const timeLeft = threeDaysInMs - (Date.now() - user.createdAt);
    return Math.max(0, Math.ceil(timeLeft / (1000 * 60 * 60 * 24)));
  };

  // Helper to get color styles based on view
  const getViewStyles = (view: AppView) => {
    switch (view) {
      case AppView.PLANNER:
        return {
          active: 'bg-purple-50 text-purple-700 border-purple-600 ring-2 ring-purple-100 dark:bg-purple-900/20 dark:text-purple-400 dark:border-purple-500 dark:ring-purple-900/30',
          hover: 'hover:text-purple-600 hover:bg-purple-50 dark:hover:bg-purple-900/10',
          icon: BrainCircuit,
          label: 'Plano'
        };
      case AppView.TIMER:
        return {
          active: 'bg-red-50 text-red-700 border-red-600 ring-2 ring-red-100 dark:bg-red-900/20 dark:text-red-400 dark:border-red-500 dark:ring-red-900/30',
          hover: 'hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10',
          icon: TimerIcon,
          label: 'Foco'
        };
      case AppView.COACH:
        return {
          active: 'bg-blue-50 text-blue-700 border-blue-600 ring-2 ring-blue-100 dark:bg-blue-900/20 dark:text-blue-400 dark:border-blue-500 dark:ring-blue-900/30',
          hover: 'hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/10',
          icon: MessageCircle,
          label: 'Coach'
        };
      case AppView.DASHBOARD:
      default:
        return {
          active: 'bg-indigo-50 text-indigo-700 border-indigo-600 ring-2 ring-indigo-100 dark:bg-indigo-900/20 dark:text-indigo-400 dark:border-indigo-500 dark:ring-indigo-900/30',
          hover: 'hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/10',
          icon: LayoutDashboard,
          label: 'Início'
        };
    }
  };

  const NavButton = ({ view }: { view: AppView }) => {
    const styles = getViewStyles(view);
    const Icon = styles.icon;
    const isActive = currentView === view;

    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`flex flex-col items-center justify-center px-5 py-3 rounded-xl transition-all duration-300 w-full sm:w-auto border-2 ${
          isActive
            ? `${styles.active} shadow-lg scale-105 font-bold`
            : `bg-white dark:bg-slate-900 border-transparent text-slate-500 dark:text-slate-400 ${styles.hover}`
        }`}
