import React, { useState, useEffect, useCallback, useRef } from 'react';
import Button from './Button';
import { Play, Pause, RotateCcw, Coffee, Zap, Timer as TimerIcon, Volume2, VolumeX, Bell } from 'lucide-react';

type TimerPreset = 'classic' | 'sprint';

const DURATIONS = {
  classic: { work: 25 * 60, break: 5 * 60 },
  sprint: { work: 50 * 60, break: 10 * 60 },
};

const Timer: React.FC = () => {
  const [preset, setPreset] = useState<TimerPreset>('classic');
  const [mode, setMode] = useState<'work' | 'break'>('work');
  const [timeLeft, setTimeLeft] = useState(DURATIONS.classic.work);
  const [isActive, setIsActive] = useState(false);
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [visualAlert, setVisualAlert] = useState<{ message: string; type: 'work' | 'break' } | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);

  const currentWorkTime = DURATIONS[preset].work;
  const currentBreakTime = DURATIONS[preset].break;

  const playNotificationSound = useCallback((isWorkEnding: boolean) => {
    if (!soundEnabled) return;

    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const ctx = audioContextRef.current;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();

      osc.type = 'sine';
      osc.frequency.setValueAtTime(isWorkEnding ? 440 : 660, ctx.currentTime);
      osc.frequency.exponentialRampToValueAtTime(isWorkEnding ? 220 : 880, ctx.currentTime + 0.5);

      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + 0.1);
      gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.5);

      osc.connect(gain);
      gain.connect(ctx.destination);

      osc.start();
      osc.stop(ctx.currentTime + 0.5);
    } catch (e) {
      console.warn("Audio context error", e);
    }
  }, [soundEnabled]);

  const toggleTimer = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    setIsActive(!isActive);
  }, [isActive]);

  const resetTimer = useCallback(() => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? currentWorkTime : currentBreakTime);
    setVisualAlert(null);
  }, [mode, currentWorkTime, currentBreakTime]);

  const switchMode = useCallback((newMode: 'work' | 'break', autoTrigger = false) => {
    setMode(newMode);
    setIsActive(false);
    setTimeLeft(newMode === 'work' ? DURATIONS[preset].work : DURATIONS[preset].break);

    if (autoTrigger) {
      const msg = newMode === 'break' ? 'Trabalho Concluído! Hora de descansar.' : 'Pausa encerrada! De volta ao foco.';
      setVisualAlert({ message: msg, type: newMode });
      playNotificationSound(newMode === 'break');

      setTimeout(() => setVisualAlert(null), 5000);
    }
  }, [preset, playNotificationSound]);

  const changePreset = (newPreset: TimerPreset) => {
    setPreset(newPreset);
    setMode('work');
    setIsActive(false);
    setTimeLeft(DURATIONS[newPreset].work);
    setVisualAlert(null);
  };

  useEffect(() => {
    let interval: number | null = null;

    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((time) => time - 1);
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      if (mode === 'work') switchMode('break', true);
      else switchMode('work', true);
    }

    return () => {
      if (interval) clearInterval(interval);
    };
  }, [isActive, timeLeft, mode, switchMode]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const totalTime = mode === 'work' ? currentWorkTime : currentBreakTime;
  const progress = ((totalTime - timeLeft) / totalTime) * 100;

  // Circular progress properties
  const radius = 120;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (progress / 100) * circumference;

  return (
    <div className="max-w-md mx-auto text-center relative">
      {visualAlert && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-50 animate-bounce`}>
          <div className={`px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 border-2 ${
            visualAlert.type === 'break' 
              ? 'bg-green-600 border-green-400 text-white dark:bg-green-700' 
              : 'bg-indigo-600 border-indigo-400 text-white dark:bg-indigo-700'
          }`}>
            <Bell className="w-5 h-5 animate-ring" />
            <span className="font-bold">{visualAlert.message}</span>
          </div>
        </div>
      )}

      <div className="mb-8">
        <h2 className="text-3xl font-bold text-slate-900 dark:text-slate-100 mb-2">Timer de Foco</h2>
        <p className="text-slate-600 dark:text-slate-400">Mantenha a disciplina com lembretes inteligentes.</p>
      </div>

      <div className="flex items-center justify-center gap-4 mb-6">
        <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl w-fit">
          <button
            onClick={() => changePreset('classic')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${
              preset === 'classic' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
            }`}
          >
            25/5
          </button>
          <button
            onClick={() => changePreset('sprint')}
            className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${
              preset === 'sprint' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 dark:text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'
            }`}
          >
            50/10
          </button>
        </div>

        <button
          onClick={() => setSoundEnabled(!soundEnabled)}
          className={`p-2.5 rounded-xl border transition-all ${
            soundEnabled 
              ? 'bg-indigo-50 border-indigo-200 text-indigo-600 dark:bg-indigo-900/30 dark:border-indigo-800 dark:text-indigo-400' 
              : 'bg-slate-50 border-slate-200 text-slate-400 dark:bg-slate-800 dark:border-slate-700 dark:text-slate-600'
          }`}
          title={soundEnabled ? "Desativar som" : "Ativar som"}
        >
          {soundEnabled ? <Volume2 className="w-5 h-5" /> : <VolumeX className="w-5 h-5" />}
        </button>
      </div>

      <div className={`bg-white dark:bg-slate-900 rounded-3xl shadow-xl p-8 border-2 transition-all duration-500 relative overflow-hidden flex flex-col items-center ${
        visualAlert ? 'scale-105 ring-4 ring-indigo-200 dark:ring-indigo-900/40' : ''
      } ${mode === 'work' ? 'border-slate-200 dark:border-slate-800' : 'border-green-100 dark:border-green-900/30'}`}>

        {/* Horizontal background bar for extra subtle feedback */}
        <div 
          className={`absolute bottom-0 left-0 h-1 transition-all duration-1000 ease-linear ${mode === 'work' ? 'bg-indigo-500' : 'bg-green-500'}`}
          style={{ width: `${progress}%` }}
        />

        <div className="flex justify-center gap-4 mb-4 z-10">
          <button
            onClick={() => switchMode('work')}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold transition-colors ${
              mode === 'work' 
                ? 'bg-indigo-100 dark:bg-indigo-900/40 text-indigo-700 dark:text-indigo-400' 
                : 'text-slate-500 dark:text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
            }`}
          >
            <Zap className="w-4 h-4" /> Trabalho
          </button>
          <button
            onClick={() => switchMode('break')}
            className={`flex items-center gap-2 px-4 py-2 rounded-full text-sm font-semibold transition-colors ${
              mode === 'break' 
                ? 'bg-green-100 dark:bg-green-900/40 text-green-700 dark:text-green-400' 
                : 'text-slate-500 dark:text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-800'
            }`}
          >
            <Coffee className="w-4 h-4" /> Pausa
          </button>
        </div>

        {/* Circular Progress Container */}
        <div className="relative flex items-center justify-center w-64 h-64 mb-6">
          <svg className="w-full h-full -rotate-90 transform" viewBox="0 0 260 260">
            {/* Background Circle */}
            <circle
              className="text-slate-100 dark:text-slate-800 transition-colors"
              strokeWidth="12"
              stroke="currentColor"
              fill="transparent"
              r={radius}
              cx="130"
              cy="130"
            />
            {/* Progress Circle */}
            <circle
              className={`transition-all duration-1000 ease-linear ${mode === 'work' ? 'text-indigo-600 dark:text-indigo-500' : 'text-green-600 dark:text-green-500'}`}
              strokeWidth="12"
              strokeDasharray={circumference}
              style={{ strokeDashoffset }}
              strokeLinecap="round"
              stroke="currentColor"
              fill="transparent"
              r={radius}
              cx="130"
              cy="130"
            />
          </svg>

          <div className={`absolute text-6xl font-bold tabular-nums tracking-tighter transition-colors duration-500 ${mode === 'work' ? 'text-slate-800 dark:text-slate-100' : 'text-green-600 dark:text-green-400'}`}>
            {formatTime(timeLeft)}
          </div>
        </div>

        <div className="flex justify-center gap-4 z-10">
          <Button 
            onClick={toggleTimer} 
            className={`w-32 py-3 rounded-xl text-lg ${mode === 'break' && isActive ? 'bg-green-600 hover:bg-green-700 dark:bg-green-700 dark:hover:bg-green-800' : ''}`}
          >
            {isActive ? (
              <>
                <Pause className="w-5 h-5 mr-2" /> Pausar
              </>
            ) : (
              <>
                <Play className="w-5 h-5 mr-2" /> Iniciar
              </>
            )}
          </Button>

          <Button onClick={resetTimer} variant="secondary" className="px-4 py-3 rounded-xl">
            <RotateCcw className="w-5 h-5" />
          </Button>
        </div>

        <p className="mt-6 text-sm text-slate-400 dark:text-slate-500 min-h-[1.25rem] z-10">
          {isActive 
            ? (mode === 'work' ? "Mantenha o foco. Você consegue!" : "Relaxe, você mereceu.") 
            : visualAlert ? visualAlert.message : "Pronto para começar?"}
        </p>
      </div>

      <div className="mt-8 flex items-center justify-center gap-2 text-slate-400 dark:text-slate-500 text-sm">
        <TimerIcon className="w-4 h-4" />
        <span>Modo atual: <strong>{preset === 'classic' ? 'Clássico' : 'Sprint'}</strong></span>
      </div>
    </div>
  );
};

export default Timer;

import React, { useState } from 'react';
import { ProcrastinationType, ActionPlan } from '../types';
import { generateActionPlan } from '../services/geminiService';
import Button from './Button';
import { Brain, CheckCircle, ArrowRight, RefreshCw, AlertCircle, Share2, Check, Target } from 'lucide-react';

interface PlannerProps {
  title?: string;
  description?: string;
}

const Planner: React.FC<PlannerProps> = ({ 
  title = "Desbloqueio Mental", 
  description = "Identifique seu bloqueio para um plano de ação personalizado." 
}) => {
  const [task, setTask] = useState('');
  const [type, setType] = useState<ProcrastinationType>(ProcrastinationType.OVERWHELM);
  const [plan, setPlan] = useState<ActionPlan | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);

  // Regex checks for at least one letter (including Portuguese accents)
  const hasLetters = /[a-zA-ZÀ-ÿ]/.test(task);
  const isTaskValid = task.trim().length >= 3 && hasLetters;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const trimmedTask = task.trim();

    if (!trimmedTask) {
      setError("Por favor, descreva a tarefa que você está adiando.");
      return;
    }

    if (trimmedTask.length < 3) {
      setError("A descrição da tarefa é muito curta. Use pelo menos 3 caracteres.");
      return;
    }

    if (!/[a-zA-ZÀ-ÿ]/.test(trimmedTask)) {
      setError("A descrição parece inválida. Por favor, use letras para descrever sua tarefa.");
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const result = await generateActionPlan(trimmedTask, type);
      setPlan(result);
    } catch (err) {
      setError("Não foi possível gerar o plano. Verifique sua conexão ou a chave de API.");
    } finally {
      setLoading(false);
    }
  };

  const handleShare = async () => {
    if (!plan) return;

    const textToCopy = `
🎯 *Plano de Ação: ${plan.title}*
✨ "${plan.motivationalQuote}"

*Passos para agir agora:*
${plan.steps.map((step, i) => `${i + 1}. ${step}`).join('\n')}

_Gerado por AntiPro - Adeus Procrastinação_
    `.trim();

    try {
      await navigator.clipboard.writeText(textToCopy);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Falha ao copiar:', err);
      alert("Não foi possível copiar automaticamente. Selecione o texto e copie manualmente.");
    }
  };

  const reset = () => {
    setPlan(null);
    setTask('');
    setError(null);
    setCopied(false);
  };

  if (plan) {
    return (
      <div className="max-w-2xl mx-auto animate-fade-in">
        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-xl border border-indigo-50 dark:border-slate-800 overflow-hidden">
          <div className="bg-indigo-600 dark:bg-indigo-700 p-6 text-white">
            <div className="flex items-center gap-3 mb-2">
              <Target className="w-8 h-8 text-indigo-200" />
              <h2 className="text-2xl font-bold">{plan.title}</h2>
            </div>
            <p className="opacity-90 italic ml-11">"{plan.motivationalQuote}"</p>
          </div>

          <div className="p-8">
            <h3 className="text-lg font-semibold text-slate-800 dark:text-slate-100 mb-4 flex items-center gap-2">
              <CheckCircle className="w-5 h-5 text-green-500" />
              Seu Plano de Ação Imediata
            </h3>

            <div className="space-y-4">
              {plan.steps.map((step, idx) => (
                <div key={idx} className="flex gap-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800 hover:border-indigo-200 dark:hover:border-indigo-900/50 transition-colors">
                  <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 flex items-center justify-center font-bold">
                    {idx + 1}
                  </div>
                  <p className="text-slate-700 dark:text-slate-300 font-medium pt-1">{step}</p>
                </div>
              ))}
            </div>

            <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 flex flex-wrap gap-4 justify-between items-center">
              <p className="text-sm text-slate-500 dark:text-slate-400 flex-1 min-w-[200px]">Comece pelo passo 1 agora mesmo!</p>
              <div className="flex gap-2 w-full sm:w-auto">
                <Button 
                  onClick={handleShare} 
                  variant="secondary" 
                  className={`flex-1 sm:flex-none transition-all ${copied ? 'border-green-500 text-green-600 bg-green-50 dark:bg-green-900/20 dark:text-green-400 dark:border-green-800' : ''}`}
                >
                  {copied ? (
                    <>
                      <Check className="w-4 h-4 mr-2" />
                      Copiado!
                    </>
                  ) : (
                    <>
                      <Share2 className="w-4 h-4 mr-2" />
                      Compartilhar
                    </>
                  )}
                </Button>
                <Button onClick={reset} variant="secondary" className="flex-1 sm:flex-none">
                  <RefreshCw className="w-4 h-4 mr-2" />
                  Novo Plano
                </Button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-bold text-slate-900 dark:text-slate-100 mb-3">{title}</h2>
        <p className="text-slate-600 dark:text-slate-400">{description}</p>
      </div>

      <div className="bg-white dark:bg-slate-900 p-8 rounded-2xl shadow-lg border border-slate-200 dark:border-slate-800 transition-colors duration-300">
        <form onSubmit={handleSubmit} className="space-y-6">

          <div>
            <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
              O que você precisa fazer?
            </label>
            <input
              type="text"
              value={task}
              onChange={(e) => {
                setTask(e.target.value);
                if (error) setError(null);
              }}
              placeholder="Ex: Começar a estudar para a prova..."
              className={`w-full px-4 py-3 rounded-xl border focus:ring-2 outline-none transition-all dark:bg-slate-800 dark:text-slate-100 ${
