export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Button from './Button';
import { 
  Play, Pause, RotateCcw, Coffee, Zap, Timer as TimerIcon, 
  Volume2, VolumeX, Bell, Maximize2, Minimize2, Wind, CloudRain, Waves, Square
} from 'lucide-react';

type TimerPreset = 'classic' | 'sprint';
type AmbientSound = 'none' | 'white' | 'rain' | 'waves';

const DURATIONS = {
  classic: { work: 25 * 60, break: 5 * 60 },
  sprint: { work: 50 * 60, break: 10 * 60 },
};

const Timer: React.FC = () => {
  const [preset, setPreset] = useState<TimerPreset>('classic');
  const [mode, setMode] = useState<'work' | 'break'>('work');
  const [timeLeft, setTimeLeft] = useState(DURATIONS.classic.work);
  const [isActive, setIsActive] = useState(false);
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [isFocusMode, setIsFocusMode] = useState(false);
  const [ambientSound, setAmbientSound] = useState<AmbientSound>('none');
  const [visualAlert, setVisualAlert] = useState<{ message: string; type: 'work' | 'break' } | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const ambientSourceRef = useRef<AudioNode | null>(null);
  const ambientGainRef = useRef<GainNode | null>(null);

  const currentWorkTime = DURATIONS[preset].work;
  const currentBreakTime = DURATIONS[preset].break;

  // Sound Engine for Ambient Noise
  const stopAmbientSound = useCallback(() => {
    if (ambientSourceRef.current) {
      ambientSourceRef.current.disconnect();
      ambientSourceRef.current = null;
    }
  }, []);

  const playAmbientSound = useCallback((type: AmbientSound) => {
    stopAmbientSound();
    if (type === 'none') return;

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    const ctx = audioContextRef.current;

    // Create buffer for noise
    const bufferSize = 2 * ctx.sampleRate;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const output = buffer.getChannelData(0);

    for (let i = 0; i < bufferSize; i++) {
      if (type === 'white') {
        output[i] = Math.random() * 2 - 1;
      } else if (type === 'rain') {
        // Filtered noise for rain effect
        output[i] = (Math.random() * 2 - 1) * 0.5; 
      } else if (type === 'waves') {
        // Low frequency noise
        output[i] = (Math.random() * 2 - 1) * 0.8;
      }
    }

    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.loop = true;

    const biquadFilter = ctx.createBiquadFilter();
    biquadFilter.type = type === 'waves' ? 'lowpass' : 'bandpass';
    biquadFilter.frequency.value = type === 'rain' ? 1000 : (type === 'waves' ? 400 : 800);
    biquadFilter.Q.value = 1;

    const gainNode = ctx.createGain();
    gainNode.gain.setValueAtTime(0, ctx.currentTime);
    gainNode.gain.linearRampToValueAtTime(0.15, ctx.currentTime + 2); // Fade in

    source.connect(biquadFilter);
    biquadFilter.connect(gainNode);
    gainNode.connect(ctx.destination);

    source.start();
    ambientSourceRef.current = source;
    ambientGainRef.current = gainNode;
  }, [stopAmbientSound]);

  useEffect(() => {
    if (isFocusMode && ambientSound !== 'none') {
      playAmbientSound(ambientSound);
    } else {
      stopAmbientSound();
    }
    return () => stopAmbientSound();
  }, [isFocusMode, ambientSound, playAmbientSound, stopAmbientSound]);

  const playNotificationSound = useCallback((isWorkEnding: boolean) => {
    if (!soundEnabled) return;
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }
      const ctx = audioContextRef.current;
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = 'sine';
      osc.frequency.setValueAtTime(isWorkEnding ? 440 : 660, ctx.currentTime);
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.2, ctx.currentTime + 0.1);
      gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.5);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start();
      osc.stop(ctx.currentTime + 0.5);
    } catch (e) { console.warn(e); }
  }, [soundEnabled]);

  const toggleTimer = useCallback(() => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    }
    setIsActive(!isActive);
  }, [isActive]);

  const resetTimer = useCallback(() => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? currentWorkTime : currentBreakTime);
    setVisualAlert(null);
  }, [mode, currentWorkTime, currentBreakTime]);

  const switchMode = useCallback((newMode: 'work' | 'break', autoTrigger = false) => {
    setMode(newMode);
    setIsActive(false);
    setTimeLeft(newMode === 'work' ? DURATIONS[preset].work : DURATIONS[preset].break);
    if (autoTrigger) {
      const msg = newMode === 'break' ? 'Trabalho Concluído! Hora de descansar.' : 'Pausa encerrada! De volta ao foco.';
      setVisualAlert({ message: msg, type: newMode });
      playNotificationSound(newMode === 'break');
      setTimeout(() => setVisualAlert(null), 5000);
    }
  }, [preset, playNotificationSound]);

  useEffect(() => {
    let interval: number | null = null;
    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => {
        setTimeLeft((time) => time - 1);
      }, 1000);
    } else if (timeLeft === 0 && isActive) {
      if (mode === 'work') switchMode('break', true);
      else switchMode('work', true);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [isActive, timeLeft, mode, switchMode]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const totalTime = mode === 'work' ? currentWorkTime : currentBreakTime;
  const progressPercent = (timeLeft / totalTime) * 100;
  const radius = 110;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (progressPercent / 100) * circumference;

  // Immersive Focus Mode Overlay
  if (isFocusMode) {
    return (
      <div className={`fixed inset-0 z-[200] flex flex-col items-center justify-center transition-colors duration-1000 overflow-hidden ${
        mode === 'work' 
          ? 'bg-slate-950 text-white' 
          : 'bg-green-950 text-white'
      }`}>
        {/* Animated Background Orbs */}
        <div className="absolute inset-0 overflow-hidden pointer-events-none opacity-20">
          <div className={`absolute top-1/4 left-1/4 w-96 h-96 rounded-full blur-[120px] animate-pulse transition-colors duration-1000 ${mode === 'work' ? 'bg-indigo-600' : 'bg-green-600'}`}></div>
          <div className={`absolute bottom-1/4 right-1/4 w-96 h-96 rounded-full blur-[120px] animate-pulse transition-colors duration-1000 delay-1000 ${mode === 'work' ? 'bg-purple-600' : 'bg-emerald-600'}`}></div>
        </div>

        <button 
          onClick={() => setIsFocusMode(false)}
          className="absolute top-8 right-8 p-3 rounded-full bg-white/10 hover:bg-white/20 transition-all text-white/60 hover:text-white"
        >
          <Minimize2 className="w-6 h-6" />
        </button>

        <div className="mb-12 text-center z-10">
          <h2 className="text-sm font-bold uppercase tracking-[0.3em] text-white/40 mb-2">
            {mode === 'work' ? 'Estado de Foco Profundo' : 'Recuperação de Energia'}
          </h2>
          <div className="h-1 w-12 bg-white/20 mx-auto rounded-full"></div>
        </div>

        {/* Large Immersive Timer */}
        <div className="relative flex items-center justify-center w-80 h-80 sm:w-96 sm:h-96 mb-12 z-10">
          <svg className="w-full h-full -rotate-90 transform" viewBox="0 0 260 260">
            <circle className="text-white/5" strokeWidth="6" stroke="currentColor" fill="transparent" r={radius} cx="130" cy="130" />
            <circle
              className={`transition-all duration-1000 ease-linear ${mode === 'work' ? 'text-indigo-500 shadow-[0_0_20px_rgba(99,102,241,0.5)]' : 'text-green-500 shadow-[0_0_20px_rgba(34,197,94,0.5)]'}`}
              strokeWidth="8"
              strokeDasharray={circumference}
              style={{ strokeDashoffset: strokeDashoffset }}
              strokeLinecap="round"
              stroke="currentColor"
              fill="transparent"
              r={radius}
              cx="130"
              cy="130"
            />
          </svg>
          <div className="absolute flex flex-col items-center justify-center">
            <span className="text-8xl sm:text-9xl font-black tabular-nums tracking-tighter drop-shadow-2xl">
              {formatTime(timeLeft)}
            </span>
          </div>
        </div>

        <div className="flex flex-col items-center gap-10 z-10 w-full max-w-md px-6">
          <div className="flex gap-4">
             <Button 
                onClick={toggleTimer} 
                className={`w-48 py-5 rounded-full text-xl font-bold shadow-2xl transition-all active:scale-95 ${
                  isActive 
                    ? 'bg-white/10 text-white hover:bg-white/20' 
                    : mode === 'work' ? 'bg-indigo-600 text-white hover:bg-indigo-500' : 'bg-green-600 text-white hover:bg-green-500'
                }`}
              >
                {isActive ? <Pause className="w-6 h-6 mr-2" /> : <Play className="w-6 h-6 mr-2 fill-current" />}
                {isActive ? 'Pausar' : 'Iniciar'}
              </Button>
              <Button 
                onClick={resetTimer} 
                variant="ghost" 
                className="w-16 h-16 rounded-full bg-white/5 text-white/60 hover:bg-white/10 hover:text-white"
              >
                <RotateCcw className="w-6 h-6" />
              </Button>
          </div>

          {/* Ambient Sound Controls */}
          <div className="flex flex-col items-center gap-4 bg-white/5 p-6 rounded-3xl backdrop-blur-md border border-white/10 w-full">
            <p className="text-xs font-bold text-white/40 uppercase tracking-widest">Sons de Concentração</p>
