                { id: 'rain', icon: CloudRain, label: 'Chuva' },
                { id: 'waves', icon: Waves, label: 'Ondas' }
              ].map((sound) => (
                <button
                  key={sound.id}
                  onClick={() => setAmbientSound(sound.id as AmbientSound)}
                  className={`flex-1 flex flex-col items-center gap-2 p-3 rounded-2xl transition-all ${
