import React, { useState, useEffect } from 'react';
import { ProcrastinationType, ActionPlan } from '../types';
import { generateActionPlan } from '../services/geminiService';
import Button from './Button';
import { Brain, CheckCircle, ArrowRight, RefreshCw, AlertCircle, Share2, Check, Target, BrainCircuit, Sparkles, Loader2, Wand2 } from 'lucide-react';

interface PlannerProps {
  title?: string;
  description?: string;
}

const Planner: React.FC<PlannerProps> = ({ 
  title = "Desbloqueio Mental", 
  description = "Identifique seu bloqueio para um plano de ação personalizado." 
}) => {
  const [task, setTask] = useState('');
  const [type, setType] = useState<ProcrastinationType>(ProcrastinationType.OVERWHELM);
  const [plan, setPlan] = useState<ActionPlan | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [loadingStep, setLoadingStep] = useState(0);

  const loadingMessages = [
    "Analisando seu bloqueio...",
    "Identificando padrões de comportamento...",
    "Consultando estratégias de foco...",
    "Quebrando tarefas em passos simples...",
    "Finalizando seu plano personalizado..."
  ];

  useEffect(() => {
    let interval: number;
    if (loading) {
      interval = window.setInterval(() => {
        setLoadingStep((prev) => (prev + 1) % loadingMessages.length);
      }, 1500);
    } else {
      setLoadingStep(0);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const trimmedTask = task.trim();

    if (!trimmedTask || trimmedTask.length < 3) {
      setError("Por favor, descreva a tarefa (mínimo 3 caracteres).");
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const result = await generateActionPlan(trimmedTask, type);
      setPlan(result);
    } catch (err) {
      setError("Não foi possível gerar o plano. Verifique sua conexão.");
    } finally {
      setLoading(false);
    }
  };

  const handleShare = async () => {
    if (!plan) return;
    const textToCopy = `🎯 *Plano de Ação: ${plan.title}*\n✨ "${plan.motivationalQuote}"\n\n*Passos:*\n${plan.steps.map((s, i) => `${i + 1}. ${s}`).join('\n')}`;
    try {
      await navigator.clipboard.writeText(textToCopy);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      alert("Erro ao copiar texto.");
    }
  };

  const reset = () => {
    setPlan(null);
    setTask('');
    setError(null);
  };

  if (loading) {
    return (
      <div className="max-w-2xl mx-auto py-20 flex flex-col items-center justify-center animate-fade-in bg-white dark:bg-slate-900 rounded-3xl shadow-2xl border border-indigo-50 dark:border-slate-800">
        <div className="relative mb-8">
          <div className="w-24 h-24 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-xl animate-pulse">
            <BrainCircuit className="w-12 h-12" />
          </div>
          <div className="absolute -inset-4 border-2 border-indigo-500/30 rounded-[2.5rem] animate-[ping_2s_infinite]"></div>
          <div className="absolute -top-2 -right-2 w-10 h-10 bg-white dark:bg-slate-800 rounded-full flex items-center justify-center shadow-md border border-indigo-100 dark:border-slate-700 animate-bounce">
            <Sparkles className="w-5 h-5 text-indigo-500" />
          </div>
        </div>

        <div className="text-center space-y-3 px-8">
          <h3 className="text-xl font-bold text-slate-800 dark:text-white min-h-[1.5em] transition-all duration-300">
            {loadingMessages[loadingStep]}
          </h3>
          <p className="text-slate-500 dark:text-slate-400 text-sm">
            Nossa inteligência está moldando sua produtividade.
          </p>
          <div className="flex justify-center gap-1 pt-4">
            {loadingMessages.map((_, idx) => (
              <div key={idx} className={`h-1 rounded-full transition-all duration-500 ${idx === loadingStep ? 'w-6 bg-indigo-600' : 'w-1.5 bg-slate-200 dark:bg-slate-800'}`}></div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (plan) {
    return (
      <div className="max-w-2xl mx-auto animate-fade-in">
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-2xl border border-indigo-50 dark:border-slate-800 overflow-hidden">
          <div className="bg-indigo-600 p-6 text-white text-center relative overflow-hidden">
            <div className="absolute -right-8 -top-8 opacity-10 rotate-12"><Target className="w-32 h-32" /></div>
            <h2 className="text-2xl font-bold mb-2 flex items-center justify-center gap-2">
              <Target className="w-6 h-6" /> {plan.title}
            </h2>
            <p className="opacity-90 italic text-sm">"{plan.motivationalQuote}"</p>
          </div>

          <div className="p-8">
            <div className="space-y-4">
              {plan.steps.map((step, idx) => (
                <div key={idx} className="flex gap-4 p-5 bg-slate-50 dark:bg-slate-800/40 rounded-2xl border border-slate-100 dark:border-slate-800 hover:border-indigo-200 dark:hover:border-indigo-900 transition-all group">
                  <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 dark:text-indigo-400 flex items-center justify-center font-bold text-sm">
                    {idx + 1}
                  </div>
                  <p className="text-slate-700 dark:text-slate-300 font-medium group-hover:translate-x-1 transition-transform">{step}</p>
                </div>
              ))}
            </div>

            <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 flex flex-wrap gap-4 justify-between items-center">
              <div className="flex gap-2 w-full">
                <Button onClick={handleShare} variant="secondary" className={`flex-1 ${copied ? 'border-green-500 text-green-600' : ''}`}>
                  {copied ? <><Check className="w-4 h-4 mr-2" /> Copiado</> : <><Share2 className="w-4 h-4 mr-2" /> Compartilhar</>}
