                </Button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto animate-fade-in">
      <div className="text-center mb-10">
        <h2 className="text-3xl font-black text-slate-900 dark:text-slate-100 mb-3 tracking-tight">{title}</h2>
        <p className="text-slate-600 dark:text-slate-400">{description}</p>
      </div>

      <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800">
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">O que você está adiando?</label>
            <textarea
              value={task}
              onChange={(e) => {
                setTask(e.target.value);
                if (error) setError(null);
              }}
              placeholder="Ex: Começar o relatório mensal de vendas..."
              className="w-full px-4 py-4 rounded-2xl border border-slate-200 dark:border-slate-700 dark:bg-slate-800 dark:text-white focus:ring-2 focus:ring-indigo-500 outline-none transition-all resize-none h-32"
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 dark:text-slate-300 mb-2">Por que você acha que está travado?</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
              {Object.values(ProcrastinationType).map((t) => (
                <button
                  key={t}
                  type="button"
                  onClick={() => setType(t)}
                  className={`px-4 py-3 rounded-xl text-left text-sm font-medium transition-all border-2 ${
                    type === t 
                      ? 'bg-indigo-50 dark:bg-indigo-900/30 border-indigo-600 text-indigo-700 dark:text-indigo-400 shadow-sm' 
                      : 'bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:border-slate-200'
                  }`}
                >
