                </button>
              ))}
            </div>
          </div>

          {error && (
            <div className="p-4 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-xl text-sm flex items-center gap-2 animate-shake">
              <AlertCircle className="w-4 h-4" /> {error}
            </div>
          )}

          <Button 
            type="submit" 
            className="w-full py-4 text-lg font-bold group" 
            isLoading={loading}
          >
            <Wand2 className="w-5 h-5 mr-2 group-hover:rotate-12 transition-transform" /> 
