import { GoogleGenAI, Chat, GenerateContentResponse, Type } from "@google/genai";
import { ProcrastinationType, ActionPlan } from '../types';

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
const MODEL_NAME = 'gemini-3-flash-preview';

export const generateActionPlan = async (task: string, type: ProcrastinationType): Promise<ActionPlan> => {
  const prompt = `
    O usuário está procrastinando na seguinte tarefa: "${task}".
    O motivo principal identificado é: ${type}.

    Crie um plano de ação curto, prático e motivador para desbloquear o usuário AGORA.
    A resposta deve ser um objeto JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "Um título encorajador para o plano" },
            steps: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING },
              description: "3 a 5 passos pequenos e acionáveis para começar imediatamente" 
            },
            motivationalQuote: { type: Type.STRING, description: "Uma frase curta de impacto para motivar" }
          },
          required: ["title", "steps", "motivationalQuote"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as ActionPlan;
  } catch (error) {
    console.error("Error generating plan:", error);
    throw error;
  }
};

export const refineTaskWithIA = async (taskTitle: string): Promise<string[]> => {
  const prompt = `Quebre esta tarefa complexa em 3 ou 4 sub-tarefas atômicas e extremamente simples para alguém que está procrastinando: "${taskTitle}". Responda apenas um array JSON de strings.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });
    return JSON.parse(response.text || "[]");
  } catch (e) {
    return [taskTitle];
  }
};

