} from 'lucide-react';

const ScrumBoard: React.FC = () => {
  const [tasks, setTasks] = useState<ScrumTask[]>(() => {
    const saved = localStorage.getItem('antipro_scrum_tasks');
    return saved ? JSON.parse(saved) : [];
  });
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [sprintGoal, setSprintGoal] = useState(() => {
    return localStorage.getItem('antipro_sprint_goal') || '';
  });
  const [activeTab, setActiveTab] = useState<'backlog' | 'sprint'>('sprint');
  const [isRefining, setIsRefining] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('antipro_scrum_tasks', JSON.stringify(tasks));
    localStorage.setItem('antipro_sprint_goal', sprintGoal);
  }, [tasks, sprintGoal]);

  const addTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask: ScrumTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      status: activeTab === 'backlog' ? 'backlog' : 'todo',
      priority: 'medium',
      createdAt: Date.now()
    };
    setTasks([...tasks, newTask]);
    setNewTaskTitle('');
  };

  const updateTaskStatus = (id: string, newStatus: ScrumStatus) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, status: newStatus } : t));
  };

  const deleteTask = (id: string) => {
    setTasks(tasks.filter(t => t.id !== id));
  };

  const handleRefine = async (task: ScrumTask) => {
    setIsRefining(task.id);
    try {
      const subTasks = await refineTaskWithIA(task.title);
      const newTasks: ScrumTask[] = subTasks.map((title, i) => ({
        id: `${task.id}-${i}`,
        title,
        status: task.status,
        priority: task.priority,
        createdAt: Date.now()
      }));
      setTasks(prev => [...prev.filter(t => t.id !== task.id), ...newTasks]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsRefining(null);
    }
  };

  const getTasksByStatus = (status: ScrumStatus) => tasks.filter(t => t.status === status);

  const completionRate = () => {
    const sprintTasks = tasks.filter(t => t.status !== 'backlog');
    if (sprintTasks.length === 0) return 0;
    const done = sprintTasks.filter(t => t.status === 'done').length;
    return Math.round((done / sprintTasks.length) * 100);
