                  />
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center">
              <span className="text-xs font-bold text-slate-400 uppercase mb-2">Progresso da Sprint</span>
              <div className="relative w-24 h-24 flex items-center justify-center mb-2">
                <svg className="w-full h-full -rotate-90" viewBox="0 0 100 100">
                  <circle className="text-slate-100 dark:text-slate-800" strokeWidth="8" stroke="currentColor" fill="transparent" r="40" cx="50" cy="50" />
                  <circle 
                    className="text-indigo-600 transition-all duration-1000" 
                    strokeWidth="8" strokeDasharray="251.2" style={{ strokeDashoffset: 251.2 - (completionRate() / 100) * 251.2 }} 
                    strokeLinecap="round" stroke="currentColor" fill="transparent" r="40" cx="50" cy="50" 
                  />
                </svg>
                <span className="absolute text-xl font-black text-slate-800 dark:text-white">{completionRate()}%</span>
              </div>
            </div>
          </div>

          {/* Kanban Board */}
          <div className="grid md:grid-cols-3 gap-6">
            {/* TODO */}
            <div className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h4 className="font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-slate-300"></div> A Fazer
                </h4>
                <span className="bg-slate-100 dark:bg-slate-800 text-slate-500 text-xs font-bold px-2 py-0.5 rounded-full">{getTasksByStatus('todo').length}</span>
              </div>
              <div className="bg-slate-100/50 dark:bg-slate-900/50 p-3 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-800 min-h-[400px] space-y-3">
                {getTasksByStatus('todo').map(renderTaskCard)}
                <form onSubmit={addTask} className="relative">
                  <input 
                    type="text" 
                    value={newTaskTitle}
                    onChange={(e) => setNewTaskTitle(e.target.value)}
                    placeholder="Nova tarefa na sprint..."
                    className="w-full pl-4 pr-10 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                  <button type="submit" className="absolute right-2 top-1.5 p-1.5 text-indigo-600 hover:bg-indigo-50 rounded-lg"><Plus className="w-5 h-5" /></button>
                </form>
              </div>
            </div>

            {/* DOING */}
            <div className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h4 className="font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></div> Fazendo
                </h4>
                <span className="bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 text-xs font-bold px-2 py-0.5 rounded-full">{getTasksByStatus('doing').length}</span>
              </div>
              <div className="bg-indigo-50/30 dark:bg-indigo-950/20 p-3 rounded-2xl border-2 border-dashed border-indigo-100 dark:border-indigo-900/30 min-h-[400px] space-y-3">
                {getTasksByStatus('doing').map(renderTaskCard)}
                {getTasksByStatus('doing').length === 0 && (
                  <div className="h-full flex flex-col items-center justify-center text-slate-400 py-10 opacity-50">
                    <ArrowRight className="w-8 h-8 mb-2" />
                    <p className="text-xs font-medium">Arraste algo para cá</p>
                  </div>
                )}
              </div>
            </div>

            {/* DONE */}
            <div className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h4 className="font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-green-500"></div> Concluído
                </h4>
                <span className="bg-green-50 dark:bg-green-900/40 text-green-600 text-xs font-bold px-2 py-0.5 rounded-full">{getTasksByStatus('done').length}</span>
              </div>
              <div className="bg-green-50/30 dark:bg-green-950/20 p-3 rounded-2xl border-2 border-dashed border-green-100 dark:border-green-900/30 min-h-[400px] space-y-3">
                {getTasksByStatus('done').map(renderTaskCard)}
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="bg-white dark:bg-slate-900 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm overflow-hidden">
          <div className="p-6 border-b border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50 flex flex-col sm:flex-row sm:items-center justify-between gap-4">
             <div className="flex items-center gap-3">
                <div className="p-2 bg-indigo-100 dark:bg-indigo-900/50 text-indigo-600 rounded-lg"><ClipboardList className="w-6 h-6" /></div>
                <div>
                   <h3 className="font-bold text-slate-900 dark:text-white">Product Backlog</h3>
                   <p className="text-xs text-slate-500">Onde todas as suas ideias e desejos vivem.</p>
                </div>
             </div>
             <form onSubmit={addTask} className="flex gap-2">
               <input 
                  type="text" 
                  value={newTaskTitle}
                  onChange={(e) => setNewTaskTitle(e.target.value)}
                  placeholder="Novo item no backlog..."
                  className="px-4 py-2 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full sm:w-64"
               />
               <Button type="submit" className="whitespace-nowrap"><Plus className="w-4 h-4" /></Button>
             </form>
          </div>

          <div className="p-6">
            {getTasksByStatus('backlog').length === 0 ? (
              <div className="py-20 text-center flex flex-col items-center justify-center text-slate-400">
                 <ClipboardList className="w-16 h-16 mb-4 opacity-20" />
                 <p className="font-medium">Seu backlog está limpo.</p>
                 <p className="text-xs">Não tenha medo de jogar todas as suas obrigações aqui.</p>
              </div>
            ) : (
              <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {getTasksByStatus('backlog').map(renderTaskCard)}
              </div>
            )}
          </div>

          <div className="p-4 bg-amber-50 dark:bg-amber-900/10 border-t border-amber-100 dark:border-amber-900/20 flex items-start gap-3">
            <AlertCircle className="w-5 h-5 text-amber-600 mt-0.5" />
            <p className="text-xs text-amber-800 dark:text-amber-500 leading-relaxed">
              <strong>Dica de Produtividade:</strong> O Backlog não é uma lista de cobrança. É um cérebro externo. Mova para a Sprint apenas o que você realmente se compromete a fazer no curto prazo para evitar a ansiedade do perfeccionismo.
            </p>
          </div>
        </div>
      )}
    </div>
  );
};

export default ScrumBoard;

import React, { useState, useEffect, useLayoutEffect } from 'react';
import { AppView, User } from './types';
import Planner from './components/Planner';
import Timer from './components/Timer';
import Coach from './components/Coach';
import ScrumBoard from './components/ScrumBoard';
import LandingPage from './components/LandingPage';
import Button from './components/Button';
import CheckoutModal from './components/CheckoutModal';
import { LayoutDashboard, Timer as TimerIcon, MessageCircle, BrainCircuit, Moon, Sun, Lock, LogOut, Star, Layers } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
    if (typeof window === 'undefined') return null;
    const saved = localStorage.getItem('antipro_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window === 'undefined') return false;
    const saved = localStorage.getItem('theme');
    if (saved) return saved === 'dark';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  const [isInitialized, setIsInitialized] = useState(false);
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [selectedPlan, setSelectedPlan] = useState<{name: string, price: string} | null>(null);

  useLayoutEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsInitialized(true);
    }, 400);
    return () => clearTimeout(timer);
  }, []);

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const handleRegister = (userData: { name: string; email: string; phone: string }) => {
    const newUser: User = { ...userData, createdAt: Date.now(), isSubscribed: false };
    setUser(newUser);
    localStorage.setItem('antipro_user', JSON.stringify(newUser));
    setCurrentView(AppView.DASHBOARD);
  };

  const handleLogout = () => {
    localStorage.removeItem('antipro_user');
    setUser(null);
    setCurrentView(AppView.DASHBOARD);
  };

  const handleInitiateCheckout = (planName: string, price: string) => {
    setSelectedPlan({ name: planName, price });
  };

  const handleCompleteSubscription = () => {
    if (user) {
      const updatedUser = { ...user, isSubscribed: true };
      setUser(updatedUser);
      localStorage.setItem('antipro_user', JSON.stringify(updatedUser));
      setSelectedPlan(null);
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const isTrialExpired = () => {
    if (!user) return false;
    if (user.isSubscribed) return false;
    const threeDaysInMs = 3 * 24 * 60 * 60 * 1000;
    return (Date.now() - user.createdAt) > threeDaysInMs;
  };

  const trialDaysLeft = () => {
    if (!user) return 0;
    const threeDaysInMs = 3 * 24 * 60 * 60 * 1000;
    const timeLeft = threeDaysInMs - (Date.now() - user.createdAt);
    return Math.max(0, Math.ceil(timeLeft / (1000 * 60 * 60 * 24)));
  };

  const getViewStyles = (view: AppView) => {
    switch (view) {
      case AppView.PLANNER:
        return {
          active: 'bg-purple-50 text-purple-700 border-purple-600 ring-2 ring-purple-100 dark:bg-purple-900/20 dark:text-purple-400 dark:border-purple-500 dark:ring-purple-900/30',
          hover: 'hover:text-purple-600 hover:bg-purple-50 dark:hover:bg-purple-900/10',
          icon: BrainCircuit,
          label: 'Plano'
        };
      case AppView.TIMER:
        return {
          active: 'bg-red-50 text-red-700 border-red-600 ring-2 ring-red-100 dark:bg-red-900/20 dark:text-red-400 dark:border-red-500 dark:ring-red-900/30',
          hover: 'hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/10',
          icon: TimerIcon,
          label: 'Foco'
        };
      case AppView.COACH:
        return {
          active: 'bg-blue-50 text-blue-700 border-blue-600 ring-2 ring-blue-100 dark:bg-blue-900/20 dark:text-blue-400 dark:border-blue-500 dark:ring-blue-900/30',
          hover: 'hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/10',
          icon: MessageCircle,
          label: 'Coach'
        };
      case AppView.SCRUM:
        return {
          active: 'bg-indigo-50 text-indigo-700 border-indigo-600 ring-2 ring-indigo-100 dark:bg-indigo-900/20 dark:text-indigo-400 dark:border-indigo-500 dark:ring-indigo-900/30',
          hover: 'hover:text-indigo-600 hover:bg-indigo-50 dark:hover:bg-indigo-900/10',
          icon: Layers,
          label: 'Board'
        };
      case AppView.DASHBOARD:
      default:
        return {
          active: 'bg-slate-50 text-slate-700 border-slate-600 ring-2 ring-slate-100 dark:bg-slate-900/20 dark:text-slate-400 dark:border-slate-500 dark:ring-slate-900/30',
          hover: 'hover:text-slate-600 hover:bg-slate-50 dark:hover:bg-slate-900/10',
          icon: LayoutDashboard,
          label: 'Início'
        };
    }
  };

  const NavButton = ({ view }: { view: AppView }) => {
    const styles = getViewStyles(view);
    const Icon = styles.icon;
    const isActive = currentView === view;

    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`flex flex-col items-center justify-center px-4 py-2 rounded-xl transition-all duration-300 w-full sm:w-auto border-2 ${
          isActive
            ? `${styles.active} shadow-lg scale-105 font-bold`
            : `bg-white dark:bg-slate-900 border-transparent text-slate-500 dark:text-slate-400 ${styles.hover}`
        }`}
      >
        <Icon className={`w-5 h-5 mb-1 ${isActive ? 'stroke-2' : 'stroke-1.5'}`} />
        <span className="text-[10px] uppercase font-bold tracking-tighter">{styles.label}</span>
      </button>
    );
  };

  if (!isInitialized) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
        <div className="relative">
          <div className="w-24 h-24 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-white shadow-2xl animate-pulse">
            <BrainCircuit className="w-12 h-12" />
          </div>
          <div className="absolute -inset-4 bg-indigo-500/20 rounded-full blur-2xl animate-pulse -z-10"></div>
        </div>
        <div className="mt-8 flex flex-col items-center gap-2">
          <h1 className="text-2xl font-black text-slate-900 dark:text-white tracking-tighter">AntiPro</h1>
          <div className="flex gap-1">
            <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
            <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
            <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce"></div>
          </div>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 transition-colors duration-300 animate-fade-in">
        <header className="max-w-6xl mx-auto px-4 h-20 flex items-center justify-between">
           <div className="flex items-center gap-3 font-bold text-xl text-slate-900 dark:text-slate-100">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg">
              <BrainCircuit className="w-6 h-6" />
            </div>
            <span>AntiPro</span>
          </div>
          <button onClick={toggleDarkMode} className="p-2.5 rounded-xl bg-white dark:bg-slate-900 shadow-sm border border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-400">
            {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
          </button>
        </header>
        <LandingPage onRegister={handleRegister} onDirectSubscribe={handleInitiateCheckout} />
        {selectedPlan && (
          <CheckoutModal planName={selectedPlan.name} price={selectedPlan.price} onConfirm={handleCompleteSubscription} onCancel={() => setSelectedPlan(null)} />
        )}
      </div>
    );
  }

  const renderContent = () => {
    if (isTrialExpired()) {
      return (
        <div className="max-w-4xl mx-auto px-4 py-12 animate-fade-in text-center">
          <div className="mb-8 inline-flex items-center justify-center w-20 h-20 bg-red-100 dark:bg-red-900/30 text-red-600 rounded-full"><Lock className="w-10 h-10" /></div>
          <h2 className="text-4xl font-extrabold text-slate-900 dark:text-slate-100 mb-4">Seu teste gratuito expirou</h2>
          <p className="text-xl text-slate-600 dark:text-slate-400 mb-12 max-w-2xl mx-auto">Esperamos que o AntiPro tenha ajudado você nestes últimos 3 dias. Para continuar sua jornada de produtividade, escolha um dos planos abaixo.</p>
          <div className="grid md:grid-cols-3 gap-6 text-left">
            {[{ name: 'Plano Mensal', price: '35,00', period: 'mês', highlight: false }, { name: 'Plano Semestral', price: '27,00', period: 'mês', highlight: true, badge: 'ECONOMIA' }, { name: 'Plano Anual', price: '19,90', period: 'mês', highlight: false }].map(p => (
              <div key={p.name} className={`bg-white dark:bg-slate-900 p-8 rounded-3xl border-2 shadow-lg transition-transform hover:scale-[1.02] ${p.highlight ? 'border-indigo-600 ring-4 ring-indigo-50 dark:ring-indigo-900/20' : 'border-slate-200 dark:border-slate-800'}`}>
                {p.badge && <div className="bg-indigo-600 text-white text-[10px] font-bold px-2 py-1 rounded absolute -top-3 left-1/2 -translate-x-1/2">{p.badge}</div>}
                <h3 className="text-lg font-bold mb-2 dark:text-white">{p.name}</h3>
                <p className="text-3xl font-black mb-6 dark:text-white">R$ {p.price}<span className="text-sm font-normal text-slate-500">/{p.period}</span></p>
                <Button onClick={() => handleInitiateCheckout(p.name, p.price)} variant={p.highlight ? 'primary' : 'secondary'} className="w-full">Assinar</Button>
              </div>
            ))}
          </div>
        </div>
      );
    }

    switch (currentView) {
      case AppView.PLANNER: return <Planner />;
      case AppView.TIMER: return <Timer />;
      case AppView.COACH: return <Coach />;
      case AppView.SCRUM: return <ScrumBoard />;
      case AppView.DASHBOARD:
      default:
        return (
          <div className="max-w-4xl mx-auto animate-fade-in">
            {!user.isSubscribed && (
              <div className="mb-8 p-5 bg-indigo-600 rounded-3xl text-white flex flex-col sm:flex-row items-center justify-between gap-4 shadow-xl shadow-indigo-500/20">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-white/20 rounded-2xl"><Star className="w-6 h-6 text-yellow-300 fill-yellow-300" /></div>
                  <div>
                    <p className="font-bold text-lg">Modo de Teste Ativo</p>
                    <p className="text-sm text-indigo-100">Faltam {trialDaysLeft()} dias para o fim do seu teste grátis.</p>
                  </div>
                </div>
                <Button onClick={() => setCurrentView(AppView.SUBSCRIPTION)} variant="ghost" className="w-full sm:w-auto text-white border-white/30 hover:bg-white/10 px-6">Virar Premium</Button>
              </div>
            )}

            <div className="text-center mb-12">
              <h1 className="text-4xl md:text-5xl font-black text-slate-900 dark:text-slate-100 mb-4 tracking-tight">Olá, {user.name.split(' ')[0]}! 👋<br/><span className="text-indigo-600 dark:text-indigo-400">O que vamos conquistar hoje?</span></h1>
            </div>

            <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-4">
              <div onClick={() => setCurrentView(AppView.SCRUM)} className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border-2 border-slate-100 dark:border-slate-800 hover:border-indigo-300 hover:shadow-xl transition-all cursor-pointer group">
                <div className="w-12 h-12 rounded-2xl flex items-center justify-center mb-4 bg-indigo-100 dark:bg-indigo-900/30 text-indigo-600 transition-transform group-hover:scale-110"><Layers className="w-6 h-6" /></div>
                <h3 className="text-lg font-bold text-slate-900 dark:text-slate-100 mb-1">Scrum Board</h3>
                <p className="text-slate-500 text-xs leading-relaxed">Gerencie suas entregas e backlog de forma ágil.</p>
              </div>
              <div onClick={() => setCurrentView(AppView.PLANNER)} className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border-2 border-slate-100 dark:border-slate-800 hover:border-purple-300 hover:shadow-xl transition-all cursor-pointer group">
                <div className="w-12 h-12 rounded-2xl flex items-center justify-center mb-4 bg-purple-100 dark:bg-purple-900/30 text-purple-600 transition-transform group-hover:scale-110"><BrainCircuit className="w-6 h-6" /></div>
                <h3 className="text-lg font-bold text-slate-900 dark:text-slate-100 mb-1">IA Planner</h3>
                <p className="text-slate-500 text-xs leading-relaxed">Gere planos de ação rápidos para destravar agora.</p>
              </div>
              <div onClick={() => setCurrentView(AppView.TIMER)} className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border-2 border-slate-100 dark:border-slate-800 hover:border-red-300 hover:shadow-xl transition-all cursor-pointer group">
                <div className="w-12 h-12 rounded-2xl flex items-center justify-center mb-4 bg-red-100 dark:bg-red-900/30 text-red-600 transition-transform group-hover:scale-110"><TimerIcon className="w-6 h-6" /></div>
                <h3 className="text-lg font-bold text-slate-900 dark:text-slate-100 mb-1">Foco Pomodoro</h3>
                <p className="text-slate-500 text-xs leading-relaxed">Ciclos de foco absoluto com sons ambientes.</p>
              </div>
              <div onClick={() => setCurrentView(AppView.COACH)} className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border-2 border-slate-100 dark:border-slate-800 hover:border-blue-300 hover:shadow-xl transition-all cursor-pointer group">
                <div className="w-12 h-12 rounded-2xl flex items-center justify-center mb-4 bg-blue-100 dark:bg-blue-900/30 text-blue-600 transition-transform group-hover:scale-110"><MessageCircle className="w-6 h-6" /></div>
                <h3 className="text-lg font-bold text-slate-900 dark:text-slate-100 mb-1">Coach IA</h3>
                <p className="text-slate-500 text-xs leading-relaxed">Converse com seu assistente de produtividade.</p>
              </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors duration-300 animate-fade-in">
      <header className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 sticky top-0 z-50 shadow-sm transition-colors duration-300">
        <div className="max-w-6xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer font-bold text-xl text-slate-900 dark:text-slate-100 hover:opacity-80 transition-opacity" onClick={() => setCurrentView(AppView.DASHBOARD)}>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><BrainCircuit className="w-6 h-6" /></div>
            <span className="hidden sm:inline">AntiPro</span>
          </div>

          <div className="flex items-center gap-2 md:gap-4">
            <div className="hidden md:flex gap-1">
              <NavButton view={AppView.DASHBOARD} />
              <NavButton view={AppView.SCRUM} />
              <NavButton view={AppView.PLANNER} />
              <NavButton view={AppView.TIMER} />
              <NavButton view={AppView.COACH} />
            </div>

            <div className="flex items-center gap-2 border-l border-slate-200 dark:border-slate-700 ml-2 pl-4">
              <button onClick={toggleDarkMode} className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 transition-colors">
                {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
              </button>
              <button onClick={handleLogout} className="p-2.5 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 hover:bg-red-100 transition-colors">
                <LogOut className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </header>

      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-2 pb-safe flex justify-around z-50 shadow-lg">
        <NavButton view={AppView.DASHBOARD} />
        <NavButton view={AppView.SCRUM} />
        <NavButton view={AppView.PLANNER} />
        <NavButton view={AppView.TIMER} />
        <NavButton view={AppView.COACH} />
      </div>

      <main className="flex-1 p-4 md:p-8 pb-32 md:pb-8 max-w-6xl mx-auto w-full overflow-x-hidden">
        {renderContent()}
      </main>

      {selectedPlan && (
        <CheckoutModal planName={selectedPlan.name} price={selectedPlan.price} onConfirm={handleCompleteSubscription} onCancel={() => setSelectedPlan(null)} />
      )}
    </div>
  );
};

