import React, { useState, useEffect } from 'react';
import { ScrumTask, ScrumStatus } from '../types';
import { refineTaskWithIA } from '../services/geminiService';
import Button from './Button';
import { 
  ClipboardList, 
  Layers, 
  CheckCircle2, 
  Plus, 
  Trash2, 
  ArrowRight, 
  Sparkles, 
  Flag,
  ChevronRight,
  TrendingUp,
  AlertCircle,
  AlertTriangle,
  Circle
} from 'lucide-react';

const ScrumBoard: React.FC = () => {
  const [tasks, setTasks] = useState<ScrumTask[]>(() => {
    const saved = localStorage.getItem('antipro_scrum_tasks');
    return saved ? JSON.parse(saved) : [];
  });
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [sprintGoal, setSprintGoal] = useState(() => {
    return localStorage.getItem('antipro_sprint_goal') || '';
  });
  const [activeTab, setActiveTab] = useState<'backlog' | 'sprint'>('sprint');
  const [isRefining, setIsRefining] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('antipro_scrum_tasks', JSON.stringify(tasks));
    localStorage.setItem('antipro_sprint_goal', sprintGoal);
  }, [tasks, sprintGoal]);

  const addTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask: ScrumTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      status: activeTab === 'backlog' ? 'backlog' : 'todo',
      priority: newTaskPriority,
      createdAt: Date.now()
    };
    setTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
  };

  const updateTaskStatus = (id: string, newStatus: ScrumStatus) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, status: newStatus } : t));
  };

  const updateTaskPriority = (id: string) => {
    setTasks(tasks.map(t => {
      if (t.id === id) {
        const next: Record<string, 'low' | 'medium' | 'high'> = { low: 'medium', medium: 'high', high: 'low' };
        return { ...t, priority: next[t.priority] };
      }
      return t;
    }));
  };

  const deleteTask = (id: string) => {
    setTasks(tasks.filter(t => t.id !== id));
  };

  const handleRefine = async (task: ScrumTask) => {
    setIsRefining(task.id);
    try {
      const subTasks = await refineTaskWithIA(task.title);
      const newTasks: ScrumTask[] = subTasks.map((title, i) => ({
        id: `${task.id}-${i}`,
        title,
        status: task.status,
        priority: task.priority,
        createdAt: Date.now()
      }));
      setTasks(prev => [...prev.filter(t => t.id !== task.id), ...newTasks]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsRefining(null);
    }
  };

  const getTasksByStatus = (status: ScrumStatus) => tasks.filter(t => t.status === status);

  const completionRate = () => {
    const sprintTasks = tasks.filter(t => t.status !== 'backlog');
    if (sprintTasks.length === 0) return 0;
    const done = sprintTasks.filter(t => t.status === 'done').length;
    return Math.round((done / sprintTasks.length) * 100);
  };

  const getPriorityStyles = (priority: string) => {
    switch (priority) {
      case 'high': return 'bg-rose-100 text-rose-700 dark:bg-rose-900/30 dark:text-rose-400 border-rose-200 dark:border-rose-800';
      case 'medium': return 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 border-amber-200 dark:border-amber-800';
      default: return 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400 border-slate-200 dark:border-slate-700';
    }
  };

  const renderTaskCard = (task: ScrumTask) => (
    <div 
      key={task.id} 
      className={`bg-white dark:bg-slate-800 p-4 rounded-xl border shadow-sm hover:shadow-md transition-all group animate-fade-in ${
        task.priority === 'high' ? 'border-l-4 border-l-rose-500 border-slate-200 dark:border-slate-700' : 'border-slate-200 dark:border-slate-700'
      }`}
    >
      <div className="flex justify-between items-start gap-2 mb-2">
        <div className="flex flex-col gap-1.5 flex-1">
          <button 
            onClick={() => updateTaskPriority(task.id)}
            className={`text-[10px] font-bold uppercase w-fit px-1.5 py-0.5 rounded-md border ${getPriorityStyles(task.priority)} flex items-center gap-1 transition-colors`}
          >
            {task.priority === 'high' && <AlertTriangle className="w-3 h-3" />}
            {task.priority === 'medium' && <Circle className="w-3 h-3 fill-current" />}
            {task.priority === 'low' && <Circle className="w-3 h-3" />}
            {task.priority === 'high' ? 'Alta' : task.priority === 'medium' ? 'Média' : 'Baixa'}
          </button>
          <p className="text-sm font-medium text-slate-800 dark:text-slate-200 leading-snug">{task.title}</p>
        </div>
        <button onClick={() => deleteTask(task.id)} className="text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1">
          <Trash2 className="w-4 h-4" />
        </button>
      </div>

      <div className="flex items-center justify-between mt-auto pt-3 border-t border-slate-50 dark:border-slate-700/50">
        <div className="flex gap-1">
          {task.status !== 'done' && (
            <button 
              onClick={() => handleRefine(task)}
              disabled={isRefining === task.id}
