              title="Refinar com IA"
            >
              <Sparkles className={`w-4 h-4 ${isRefining === task.id ? 'animate-spin' : ''}`} />
            </button>
          )}
        </div>

        <div className="flex gap-1">
          {task.status === 'backlog' && (
            <button onClick={() => updateTaskStatus(task.id, 'todo')} className="text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 px-2 py-1 rounded-md hover:bg-indigo-200 dark:bg-indigo-900/40 dark:text-indigo-400">Mover p/ Sprint</button>
          )}
          {task.status === 'todo' && (
            <button onClick={() => updateTaskStatus(task.id, 'doing')} className="p-1.5 rounded-lg text-slate-400 hover:text-indigo-600 transition-colors"><ChevronRight className="w-5 h-5" /></button>
          )}
          {task.status === 'doing' && (
            <button onClick={() => updateTaskStatus(task.id, 'done')} className="p-1.5 rounded-lg text-slate-400 hover:text-green-600 transition-colors"><CheckCircle2 className="w-5 h-5" /></button>
          )}
          {task.status === 'done' && (
             <span className="text-green-500"><CheckCircle2 className="w-5 h-5 fill-current" /></span>
          )}
        </div>
      </div>
    </div>
  );

  return (
    <div className="max-w-6xl mx-auto animate-fade-in">
      <header className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-900 dark:text-slate-100 tracking-tight flex items-center gap-3">
            <Layers className="w-8 h-8 text-indigo-600" /> Metodologia Scrum
          </h2>
          <p className="text-slate-500 dark:text-slate-400 mt-1">Transforme procrastinação em ciclos de entrega real.</p>
        </div>

        <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-2xl w-fit">
          <button 
            onClick={() => setActiveTab('sprint')} 
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'sprint' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600' : 'text-slate-500'}`}
          >
            <TrendingUp className="w-4 h-4" /> Sprint Ativa
          </button>
          <button 
            onClick={() => setActiveTab('backlog')} 
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'backlog' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600' : 'text-slate-500'}`}
          >
            <ClipboardList className="w-4 h-4" /> Product Backlog
          </button>
        </div>
      </header>

      {activeTab === 'sprint' ? (
        <div className="space-y-6">
          <div className="grid md:grid-cols-3 gap-6">
            <div className="md:col-span-2 bg-indigo-600 rounded-3xl p-6 text-white shadow-xl relative overflow-hidden">
               <div className="absolute -right-4 -bottom-4 opacity-10"><Flag className="w-32 h-32" /></div>
               <div className="relative z-10">
                  <div className="flex items-center gap-2 mb-2 opacity-80">
                    <Flag className="w-4 h-4" />
                    <span className="text-xs font-bold uppercase tracking-widest">Sprint Goal (Meta)</span>
                  </div>
                  <input 
                    type="text"
                    value={sprintGoal}
                    onChange={(e) => setSprintGoal(e.target.value)}
                    placeholder="Qual o foco principal desta semana?"
                    className="bg-transparent text-xl font-bold placeholder:text-indigo-300 outline-none w-full border-b border-indigo-400 pb-1 focus:border-white transition-colors"
                  />
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center">
              <span className="text-xs font-bold text-slate-400 uppercase mb-2">Progresso da Sprint</span>
              <div className="relative w-24 h-24 flex items-center justify-center mb-2">
                <svg className="w-full h-full -rotate-90" viewBox="0 0 100 100">
                  <circle className="text-slate-100 dark:text-slate-800" strokeWidth="8" stroke="currentColor" fill="transparent" r="40" cx="50" cy="50" />
                  <circle 
                    className="text-indigo-600 transition-all duration-1000" 
                    strokeWidth="8" strokeDasharray="251.2" style={{ strokeDashoffset: 251.2 - (completionRate() / 100) * 251.2 }} 
                    strokeLinecap="round" stroke="currentColor" fill="transparent" r="40" cx="50" cy="50" 
                  />
                </svg>
                <span className="absolute text-xl font-black text-slate-800 dark:text-white">{completionRate()}%</span>
              </div>
            </div>
          </div>

          <div className="grid md:grid-cols-3 gap-6">
            {/* TODO */}
            <div className="space-y-4">
              <div className="flex items-center justify-between px-2">
                <h4 className="font-bold text-slate-700 dark:text-slate-300 flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-slate-300"></div> A Fazer
                </h4>
                <span className="bg-slate-100 dark:bg-slate-800 text-slate-500 text-xs font-bold px-2 py-0.5 rounded-full">{getTasksByStatus('todo').length}</span>
              </div>
              <div className="bg-slate-100/50 dark:bg-slate-900/50 p-3 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-800 min-h-[400px] space-y-3">
                {getTasksByStatus('todo').sort((a,b) => a.priority === 'high' ? -1 : 1).map(renderTaskCard)}
                <form onSubmit={addTask} className="space-y-2">
                  <div className="relative">
                    <input 
                      type="text" 
                      value={newTaskTitle}
                      onChange={(e) => setNewTaskTitle(e.target.value)}
                      placeholder="Nova tarefa na sprint..."
                      className="w-full pl-4 pr-10 py-3 rounded-xl border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
                    />
                    <button type="submit" className="absolute right-2 top-1.5 p-1.5 text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"><Plus className="w-5 h-5" /></button>
                  </div>
                  <div className="flex gap-2">
                    {(['low', 'medium', 'high'] as const).map(p => (
                      <button 
