import React, { useState, useEffect, useLayoutEffect } from 'react';
import { AppView, User } from './types';
import Planner from './components/Planner';
import Timer from './components/Timer';
import Coach from './components/Coach';
import ScrumBoard from './components/ScrumBoard';
import LandingPage from './components/LandingPage';
import Button from './components/Button';
import CheckoutModal from './components/CheckoutModal';
import { 
  LayoutDashboard, 
  Timer as TimerIcon, 
  MessageCircle, 
  BrainCircuit, 
  Moon, 
  Sun, 
  Lock, 
  LogOut, 
  Star, 
  Layers, 
  Trophy, 
  Zap,
  ChevronUp
} from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
    if (typeof window === 'undefined') return null;
    const saved = localStorage.getItem('antipro_user');
    if (!saved) return null;
    const parsed = JSON.parse(saved);
    // Migração de dados antigos
    if (parsed.xp === undefined) {
      parsed.xp = 0;
      parsed.level = 1;
      parsed.streak = 0;
    }
    return parsed;
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window === 'undefined') return false;
    const saved = localStorage.getItem('theme');
    if (saved) return saved === 'dark';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  const [isInitialized, setIsInitialized] = useState(false);
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [selectedPlan, setSelectedPlan] = useState<{name: string, price: string} | null>(null);
  const [showLevelUp, setShowLevelUp] = useState(false);

  useLayoutEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsInitialized(true);
    }, 400);
    return () => clearTimeout(timer);
  }, []);

  const saveUser = (updatedUser: User) => {
    setUser(updatedUser);
    localStorage.setItem('antipro_user', JSON.stringify(updatedUser));
  };

  const addXP = (amount: number) => {
    if (!user) return;
    let newXP = user.xp + amount;
    let newLevel = user.level;
    const xpToNextLevel = user.level * 1000;

    if (newXP >= xpToNextLevel) {
      newXP -= xpToNextLevel;
      newLevel += 1;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 5000);
    }

    saveUser({ ...user, xp: newXP, level: newLevel });
  };

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const handleRegister = (userData: { name: string; email: string; phone: string }) => {
    const newUser: User = { 
      ...userData, 
      createdAt: Date.now(), 
      isSubscribed: false,
      xp: 0,
      level: 1,
      streak: 1,
      lastActive: Date.now()
    };
    saveUser(newUser);
    setCurrentView(AppView.DASHBOARD);
  };

  const handleLogout = () => {
    localStorage.removeItem('antipro_user');
    setUser(null);
    setCurrentView(AppView.DASHBOARD);
  };

  const handleInitiateCheckout = (planName: string, price: string) => {
    setSelectedPlan({ name: planName, price });
  };

  const handleCompleteSubscription = () => {
    if (user) {
      saveUser({ ...user, isSubscribed: true });
      setSelectedPlan(null);
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const isTrialExpired = () => {
    if (!user) return false;
    if (user.isSubscribed) return false;
    const threeDaysInMs = 3 * 24 * 60 * 60 * 1000;
    return (Date.now() - user.createdAt) > threeDaysInMs;
  };

  const trialDaysLeft = () => {
    if (!user) return 0;
    const threeDaysInMs = 3 * 24 * 60 * 60 * 1000;
    const timeLeft = threeDaysInMs - (Date.now() - user.createdAt);
    return Math.max(0, Math.ceil(timeLeft / (1000 * 60 * 60 * 24)));
  };

  const getViewStyles = (view: AppView) => {
    switch (view) {
      case AppView.PLANNER:
        return { active: 'bg-purple-50 text-purple-700 border-purple-600 dark:bg-purple-900/20 dark:text-purple-400 dark:border-purple-500', icon: BrainCircuit, label: 'Plano' };
      case AppView.TIMER:
        return { active: 'bg-red-50 text-red-700 border-red-600 dark:bg-red-900/20 dark:text-red-400 dark:border-red-500', icon: TimerIcon, label: 'Foco' };
      case AppView.COACH:
        return { active: 'bg-blue-50 text-blue-700 border-blue-600 dark:bg-blue-900/20 dark:text-blue-400 dark:border-blue-500', icon: MessageCircle, label: 'Coach' };
      case AppView.SCRUM:
        return { active: 'bg-indigo-50 text-indigo-700 border-indigo-600 dark:bg-indigo-900/20 dark:text-indigo-400 dark:border-indigo-500', icon: Layers, label: 'Board' };
      case AppView.DASHBOARD:
      default:
        return { active: 'bg-slate-50 text-slate-700 border-slate-600 dark:bg-slate-900/20 dark:text-slate-400 dark:border-slate-500', icon: LayoutDashboard, label: 'Início' };
    }
  };

  const NavButton = ({ view }: { view: AppView }) => {
    const styles = getViewStyles(view);
    const Icon = styles.icon;
    const isActive = currentView === view;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`flex flex-col items-center justify-center px-4 py-2 rounded-xl transition-all duration-300 w-full sm:w-auto border-2 ${
          isActive
            ? `${styles.active} shadow-lg scale-105 font-bold`
            : `bg-white dark:bg-slate-900 border-transparent text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800`
        }`}
      >
        <Icon className={`w-5 h-5 mb-1 ${isActive ? 'stroke-2' : 'stroke-1.5'}`} />
        <span className="text-[10px] uppercase font-bold tracking-tighter">{styles.label}</span>
      </button>
    );
  };

  if (!isInitialized) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
        <div className="relative">
          <div className="w-24 h-24 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-white shadow-2xl animate-pulse">
            <BrainCircuit className="w-12 h-12" />
          </div>
          <div className="absolute -inset-4 bg-indigo-500/20 rounded-full blur-2xl animate-pulse -z-10"></div>
        </div>
        <div className="mt-8 flex flex-col items-center gap-2">
          <h1 className="text-2xl font-black text-slate-900 dark:text-white tracking-tighter">AntiPro</h1>
        </div>
      </div>
    );
  }

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 animate-fade-in">
        <header className="max-w-6xl mx-auto px-4 h-20 flex items-center justify-between">
           <div className="flex items-center gap-3 font-bold text-xl text-slate-900 dark:text-slate-100">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg">
              <BrainCircuit className="w-6 h-6" />
            </div>
            <span>AntiPro</span>
          </div>
          <button onClick={toggleDarkMode} className="p-2.5 rounded-xl bg-white dark:bg-slate-900 shadow-sm border border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-400">
            {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
          </button>
        </header>
        <LandingPage onRegister={handleRegister} onDirectSubscribe={handleInitiateCheckout} />
        {selectedPlan && (
          <CheckoutModal planName={selectedPlan.name} price={selectedPlan.price} onConfirm={handleCompleteSubscription} onCancel={() => setSelectedPlan(null)} />
        )}
      </div>
    );
  }

  const renderContent = () => {
    if (isTrialExpired()) {
      return (
        <div className="max-w-4xl mx-auto px-4 py-12 animate-fade-in text-center">
          <div className="mb-8 inline-flex items-center justify-center w-20 h-20 bg-red-100 dark:bg-red-900/30 text-red-600 rounded-full"><Lock className="w-10 h-10" /></div>
          <h2 className="text-4xl font-extrabold text-slate-900 dark:text-slate-100 mb-4">Seu teste gratuito expirou</h2>
          <p className="text-xl text-slate-600 dark:text-slate-400 mb-12 max-w-2xl mx-auto">Para continuar sua jornada de produtividade, escolha um dos planos abaixo.</p>
          <div className="grid md:grid-cols-3 gap-6 text-left">
            {[{ name: 'Plano Mensal', price: '35,00', period: 'mês', highlight: false }, { name: 'Plano Semestral', price: '27,00', period: 'mês', highlight: true, badge: 'ECONOMIA' }, { name: 'Plano Anual', price: '19,90', period: 'mês', highlight: false }].map(p => (
              <div key={p.name} className={`bg-white dark:bg-slate-900 p-8 rounded-3xl border-2 shadow-lg transition-transform hover:scale-[1.02] ${p.highlight ? 'border-indigo-600 ring-4 ring-indigo-50 dark:ring-indigo-900/20' : 'border-slate-200 dark:border-slate-800'}`}>
                {p.badge && <div className="bg-indigo-600 text-white text-[10px] font-bold px-2 py-1 rounded absolute -top-3 left-1/2 -translate-x-1/2">{p.badge}</div>}
                <h3 className="text-lg font-bold mb-2 dark:text-white">{p.name}</h3>
                <p className="text-3xl font-black mb-6 dark:text-white">R$ {p.price}</p>
                <Button onClick={() => handleInitiateCheckout(p.name, p.price)} variant={p.highlight ? 'primary' : 'secondary'} className="w-full">Assinar</Button>
              </div>
            ))}
          </div>
        </div>
      );
    }

    switch (currentView) {
      case AppView.PLANNER: return <Planner onComplete={() => addXP(150)} />;
      case AppView.TIMER: return <Timer onComplete={() => addXP(200)} />;
      case AppView.COACH: return <Coach />;
      case AppView.SCRUM: return <ScrumBoard onTaskDone={() => addXP(100)} />;
      case AppView.DASHBOARD:
      default:
        return (
          <div className="max-w-4xl mx-auto animate-fade-in">
            {/* Gamification Stats Header */}
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4 mb-10">
              <div className="bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex items-center gap-4">
                 <div className="w-12 h-12 bg-amber-100 dark:bg-amber-900/30 rounded-2xl flex items-center justify-center text-amber-600"><Trophy className="w-6 h-6" /></div>
                 <div>
                   <p className="text-xs font-bold text-slate-400 uppercase">Nível</p>
                   <p className="text-xl font-black text-slate-900 dark:text-white">{user.level}</p>
                 </div>
              </div>
              <div className="bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex items-center gap-4">
                 <div className="w-12 h-12 bg-indigo-100 dark:bg-indigo-900/30 rounded-2xl flex items-center justify-center text-indigo-600"><Zap className="w-6 h-6" /></div>
                 <div>
                   <p className="text-xs font-bold text-slate-400 uppercase">XP Atual</p>
                   <p className="text-xl font-black text-slate-900 dark:text-white">{user.xp}</p>
                 </div>
              </div>
              <div className="col-span-2 sm:col-span-1 bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex items-center gap-4">
                 <div className="w-12 h-12 bg-rose-100 dark:bg-rose-900/30 rounded-2xl flex items-center justify-center text-rose-600"><Star className="w-6 h-6" /></div>
                 <div>
                   <p className="text-xs font-bold text-slate-400 uppercase">Streak</p>
                   <p className="text-xl font-black text-slate-900 dark:text-white">{user.streak} dias</p>
                 </div>
              </div>
            </div>

            <div className="text-center mb-12">
              <h1 className="text-4xl md:text-5xl font-black text-slate-900 dark:text-slate-100 mb-4 tracking-tight">Olá, {user.name.split(' ')[0]}!</h1>
              <p className="text-slate-500 dark:text-slate-400 text-lg">Sua meta hoje é superar quem você era ontem.</p>
            </div>

            <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-4">
              {[
                { view: AppView.SCRUM, icon: Layers, color: 'indigo', label: 'Scrum Board', desc: 'Gerencie entregas.' },
                { view: AppView.PLANNER, icon: BrainCircuit, color: 'purple', label: 'IA Planner', desc: 'Desbloqueie agora.' },
                { view: AppView.TIMER, icon: TimerIcon, color: 'red', label: 'Foco Pomodoro', desc: 'Ciclos de foco.' },
                { view: AppView.COACH, icon: MessageCircle, color: 'blue', label: 'Coach IA', desc: 'Mentoria 24/7.' }
              ].map((item) => (
                <div key={item.view} onClick={() => setCurrentView(item.view)} className={`bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border-2 border-slate-100 dark:border-slate-800 hover:border-${item.color}-300 hover:shadow-xl transition-all cursor-pointer group`}>
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-4 bg-${item.color}-100 dark:bg-${item.color}-900/30 text-${item.color}-600 transition-transform group-hover:scale-110`}><item.icon className="w-6 h-6" /></div>
                  <h3 className="text-lg font-bold text-slate-900 dark:text-slate-100 mb-1">{item.label}</h3>
                  <p className="text-slate-500 text-xs">{item.desc}</p>
                </div>
              ))}
            </div>
          </div>
        );
    }
  };

  const xpProgress = (user.xp / (user.level * 1000)) * 100;

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
      <header className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 sticky top-0 z-50 shadow-sm">
        <div className="max-w-6xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer font-bold text-xl text-slate-900 dark:text-slate-100" onClick={() => setCurrentView(AppView.DASHBOARD)}>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><BrainCircuit className="w-6 h-6" /></div>
            <span className="hidden sm:inline">AntiPro</span>
          </div>

          <div className="flex-1 max-w-xs mx-8 hidden lg:block">
            <div className="flex items-center justify-between mb-1 text-[10px] font-bold uppercase text-slate-400">
               <span>Nível {user.level}</span>
               <span>{Math.round(xpProgress)}%</span>
            </div>
            <div className="h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
               <div className="h-full bg-indigo-600 transition-all duration-500" style={{ width: `${xpProgress}%` }}></div>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <div className="hidden md:flex gap-1">
              <NavButton view={AppView.DASHBOARD} />
              <NavButton view={AppView.SCRUM} />
              <NavButton view={AppView.PLANNER} />
              <NavButton view={AppView.TIMER} />
              <NavButton view={AppView.COACH} />
            </div>
            <div className="flex items-center gap-2 ml-4">
              <button onClick={toggleDarkMode} className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 transition-colors">
                {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
              </button>
              <button onClick={handleLogout} className="p-2.5 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 hover:bg-red-100 transition-colors">
                <LogOut className="w-5 h-5" />
              </button>
            </div>
          </div>
        </div>
      </header>

      {/* Level Up Notification Overlay */}
      {showLevelUp && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[200] animate-bounce">
          <div className="bg-indigo-600 text-white px-8 py-4 rounded-3xl shadow-2xl flex items-center gap-4 border-4 border-indigo-400">
             <Trophy className="w-10 h-10 text-yellow-300" />
             <div>
               <p className="text-xs font-black uppercase tracking-widest">Parabéns!</p>
               <h4 className="text-xl font-black">Subiu para o Nível {user.level}!</h4>
             </div>
          </div>
        </div>
      )}

      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-2 flex justify-around z-50 shadow-lg">
        <NavButton view={AppView.DASHBOARD} />
        <NavButton view={AppView.SCRUM} />
        <NavButton view={AppView.PLANNER} />
        <NavButton view={AppView.TIMER} />
        <NavButton view={AppView.COACH} />
      </div>

      <main className="flex-1 p-4 md:p-8 pb-32 md:pb-8 max-w-6xl mx-auto w-full">
        {renderContent()}
      </main>

      {selectedPlan && (
        <CheckoutModal planName={selectedPlan.name} price={selectedPlan.price} onConfirm={handleCompleteSubscription} onCancel={() => setSelectedPlan(null)} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ScrumTask, ScrumStatus } from '../types';
import { refineTaskWithIA } from '../services/geminiService';
import Button from './Button';
import { 
  ClipboardList, 
  Layers, 
  CheckCircle2, 
  Plus, 
  Trash2, 
  ArrowRight, 
  Sparkles, 
  Flag,
  ChevronRight,
  TrendingUp,
  AlertCircle,
  AlertTriangle,
  Circle
} from 'lucide-react';

interface ScrumBoardProps {
  onTaskDone?: () => void;
}

const ScrumBoard: React.FC<ScrumBoardProps> = ({ onTaskDone }) => {
  const [tasks, setTasks] = useState<ScrumTask[]>(() => {
    const saved = localStorage.getItem('antipro_scrum_tasks');
    return saved ? JSON.parse(saved) : [];
  });
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [sprintGoal, setSprintGoal] = useState(() => {
    return localStorage.getItem('antipro_sprint_goal') || '';
  });
  const [activeTab, setActiveTab] = useState<'backlog' | 'sprint'>('sprint');
  const [isRefining, setIsRefining] = useState<string | null>(null);

  useEffect(() => {
    localStorage.setItem('antipro_scrum_tasks', JSON.stringify(tasks));
    localStorage.setItem('antipro_sprint_goal', sprintGoal);
  }, [tasks, sprintGoal]);

  const addTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskTitle.trim()) return;
    const newTask: ScrumTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      status: activeTab === 'backlog' ? 'backlog' : 'todo',
      priority: newTaskPriority,
      createdAt: Date.now()
    };
    setTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setNewTaskPriority('medium');
  };

  const updateTaskStatus = (id: string, newStatus: ScrumStatus) => {
    if (newStatus === 'done') {
      onTaskDone?.();
    }
    setTasks(tasks.map(t => t.id === id ? { ...t, status: newStatus } : t));
  };

  const updateTaskPriority = (id: string) => {
    setTasks(tasks.map(t => {
      if (t.id === id) {
        const next: Record<string, 'low' | 'medium' | 'high'> = { low: 'medium', medium: 'high', high: 'low' };
        return { ...t, priority: next[t.priority] };
      }
      return t;
    }));
  };

  const deleteTask = (id: string) => {
    setTasks(tasks.filter(t => t.id !== id));
  };

  const handleRefine = async (task: ScrumTask) => {
    setIsRefining(task.id);
    try {
      const subTasks = await refineTaskWithIA(task.title);
      const newTasks: ScrumTask[] = subTasks.map((title, i) => ({
        id: `${task.id}-${i}`,
        title,
        status: task.status,
        priority: task.priority,
        createdAt: Date.now()
      }));
      setTasks(prev => [...prev.filter(t => t.id !== task.id), ...newTasks]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsRefining(null);
    }
  };

  const getTasksByStatus = (status: ScrumStatus) => tasks.filter(t => t.status === status);

  const completionRate = () => {
    const sprintTasks = tasks.filter(t => t.status !== 'backlog');
    if (sprintTasks.length === 0) return 0;
    const done = sprintTasks.filter(t => t.status === 'done').length;
    return Math.round((done / sprintTasks.length) * 100);
  };

  const getPriorityStyles = (priority: string) => {
    switch (priority) {
      case 'high': return 'bg-rose-100 text-rose-700 dark:bg-rose-900/30 dark:text-rose-400 border-rose-200 dark:border-rose-800';
      case 'medium': return 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 border-amber-200 dark:border-amber-800';
      default: return 'bg-slate-100 text-slate-600 dark:bg-slate-800 dark:text-slate-400 border-slate-200 dark:border-slate-700';
    }
  };

  const renderTaskCard = (task: ScrumTask) => (
    <div 
      key={task.id} 
      className={`bg-white dark:bg-slate-800 p-4 rounded-xl border shadow-sm hover:shadow-md transition-all group animate-fade-in ${
        task.priority === 'high' ? 'border-l-4 border-l-rose-500 border-slate-200 dark:border-slate-700' : 'border-slate-200 dark:border-slate-700'
      }`}
    >
      <div className="flex justify-between items-start gap-2 mb-2">
        <div className="flex flex-col gap-1.5 flex-1">
          <button 
            onClick={() => updateTaskPriority(task.id)}
            className={`text-[10px] font-bold uppercase w-fit px-1.5 py-0.5 rounded-md border ${getPriorityStyles(task.priority)} flex items-center gap-1 transition-colors`}
          >
            {task.priority === 'high' && <AlertTriangle className="w-3 h-3" />}
            {task.priority === 'medium' && <Circle className="w-3 h-3 fill-current" />}
            {task.priority === 'low' && <Circle className="w-3 h-3" />}
            {task.priority === 'high' ? 'Alta' : task.priority === 'medium' ? 'Média' : 'Baixa'}
          </button>
          <p className="text-sm font-medium text-slate-800 dark:text-slate-200 leading-snug">{task.title}</p>
        </div>
        <button onClick={() => deleteTask(task.id)} className="text-slate-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity p-1">
          <Trash2 className="w-4 h-4" />
        </button>
      </div>

      <div className="flex items-center justify-between mt-auto pt-3 border-t border-slate-50 dark:border-slate-700/50">
        <div className="flex gap-1">
          {task.status !== 'done' && (
            <button 
              onClick={() => handleRefine(task)}
              disabled={isRefining === task.id}
              className="p-1.5 rounded-lg text-indigo-500 hover:bg-indigo-50 dark:hover:bg-indigo-900/30 transition-colors"
              title="Refinar com IA"
            >
              <Sparkles className={`w-4 h-4 ${isRefining === task.id ? 'animate-spin' : ''}`} />
            </button>
          )}
        </div>

        <div className="flex gap-1">
          {task.status === 'backlog' && (
            <button onClick={() => updateTaskStatus(task.id, 'todo')} className="text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 px-2 py-1 rounded-md hover:bg-indigo-200 dark:bg-indigo-900/40 dark:text-indigo-400">Mover p/ Sprint</button>
          )}
          {task.status === 'todo' && (
            <button onClick={() => updateTaskStatus(task.id, 'doing')} className="p-1.5 rounded-lg text-slate-400 hover:text-indigo-600 transition-colors"><ChevronRight className="w-5 h-5" /></button>
          )}
          {task.status === 'doing' && (
            <button onClick={() => updateTaskStatus(task.id, 'done')} className="p-1.5 rounded-lg text-slate-400 hover:text-green-600 transition-colors"><CheckCircle2 className="w-5 h-5" /></button>
          )}
          {task.status === 'done' && (
             <span className="text-green-500"><CheckCircle2 className="w-5 h-5 fill-current" /></span>
          )}
        </div>
      </div>
    </div>
  );

  return (
    <div className="max-w-6xl mx-auto animate-fade-in">
      <header className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h2 className="text-3xl font-black text-slate-900 dark:text-slate-100 tracking-tight flex items-center gap-3">
            <Layers className="w-8 h-8 text-indigo-600" /> Metodologia Scrum
          </h2>
          <p className="text-slate-500 dark:text-slate-400 mt-1">Sua produtividade em ciclos ágeis.</p>
        </div>

        <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-2xl w-fit">
          <button onClick={() => setActiveTab('sprint')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'sprint' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600' : 'text-slate-500'}`}><TrendingUp className="w-4 h-4" /> Sprint</button>
          <button onClick={() => setActiveTab('backlog')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${activeTab === 'backlog' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600' : 'text-slate-500'}`}><ClipboardList className="w-4 h-4" /> Backlog</button>
        </div>
      </header>

      {activeTab === 'sprint' ? (
        <div className="space-y-6">
          <div className="grid md:grid-cols-3 gap-6">
            <div className="md:col-span-2 bg-indigo-600 rounded-3xl p-6 text-white shadow-xl relative overflow-hidden">
               <div className="absolute -right-4 -bottom-4 opacity-10"><Flag className="w-32 h-32" /></div>
               <div className="relative z-10">
                  <div className="flex items-center gap-2 mb-2 opacity-80"><Flag className="w-4 h-4" /><span className="text-xs font-bold uppercase tracking-widest">Sprint Goal</span></div>
                  <input value={sprintGoal} onChange={(e) => setSprintGoal(e.target.value)} placeholder="Qual o foco desta semana?" className="bg-transparent text-xl font-bold placeholder:text-indigo-300 outline-none w-full border-b border-indigo-400 pb-1 focus:border-white transition-colors" />
               </div>
            </div>
            <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col items-center justify-center">
              <span className="text-xs font-bold text-slate-400 uppercase mb-2">Progresso</span>
              <div className="relative w-24 h-24 flex items-center justify-center mb-2">
                <svg className="w-full h-full -rotate-90" viewBox="0 0 100 100">
                  <circle className="text-slate-100 dark:text-slate-800" strokeWidth="8" stroke="currentColor" fill="transparent" r="40" cx="50" cy="50" />
                  <circle className="text-indigo-600 transition-all duration-1000" strokeWidth="8" strokeDasharray="251.2" style={{ strokeDashoffset: 251.2 - (completionRate() / 100) * 251.2 }} strokeLinecap="round" stroke="currentColor" fill="transparent" r="40" cx="50" cy="50" />
                </svg>
                <span className="absolute text-xl font-black text-slate-800 dark:text-white">{completionRate()}%</span>
              </div>
