import React, { useState, useEffect, useCallback, useRef } from 'react';
import Button from './Button';
import { 
  Play, Pause, RotateCcw, Coffee, Zap, Timer as TimerIcon, 
  Volume2, VolumeX, Bell, Maximize2, Minimize2, Wind, CloudRain, Waves, Square
} from 'lucide-react';

type TimerPreset = 'classic' | 'sprint';
type AmbientSound = 'none' | 'white' | 'rain' | 'waves';

interface TimerProps {
  onComplete?: () => void;
}

const DURATIONS = {
  classic: { work: 25 * 60, break: 5 * 60 },
  sprint: { work: 50 * 60, break: 10 * 60 },
};

const Timer: React.FC<TimerProps> = ({ onComplete }) => {
  const [preset, setPreset] = useState<TimerPreset>('classic');
  const [mode, setMode] = useState<'work' | 'break'>('work');
  const [timeLeft, setTimeLeft] = useState(DURATIONS.classic.work);
  const [isActive, setIsActive] = useState(false);
  const [soundEnabled, setSoundEnabled] = useState(true);
  const [isFocusMode, setIsFocusMode] = useState(false);
  const [ambientSound, setAmbientSound] = useState<AmbientSound>('none');
  const [visualAlert, setVisualAlert] = useState<{ message: string; type: 'work' | 'break' } | null>(null);

  const audioContextRef = useRef<AudioContext | null>(null);
  const ambientSourceRef = useRef<AudioNode | null>(null);
  const ambientGainRef = useRef<GainNode | null>(null);

  const currentWorkTime = DURATIONS[preset].work;
  const currentBreakTime = DURATIONS[preset].break;

  const stopAmbientSound = useCallback(() => {
    if (ambientSourceRef.current) {
      ambientSourceRef.current.disconnect();
      ambientSourceRef.current = null;
    }
  }, []);

  const playAmbientSound = useCallback((type: AmbientSound) => {
    stopAmbientSound();
    if (type === 'none') return;
    if (!audioContextRef.current) audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    const ctx = audioContextRef.current;
    const bufferSize = 2 * ctx.sampleRate;
    const buffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
    const output = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      output[i] = (Math.random() * 2 - 1) * (type === 'white' ? 1 : 0.6);
    }
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.loop = true;
    const gainNode = ctx.createGain();
    gainNode.gain.setValueAtTime(0, ctx.currentTime);
    gainNode.gain.linearRampToValueAtTime(0.15, ctx.currentTime + 2);
    source.connect(gainNode);
    gainNode.connect(ctx.destination);
    source.start();
    ambientSourceRef.current = source;
  }, [stopAmbientSound]);

  useEffect(() => {
    if (isFocusMode && ambientSound !== 'none') playAmbientSound(ambientSound);
    else stopAmbientSound();
    return () => stopAmbientSound();
  }, [isFocusMode, ambientSound, playAmbientSound, stopAmbientSound]);

  const toggleTimer = useCallback(() => setIsActive(!isActive), [isActive]);
  const resetTimer = useCallback(() => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? currentWorkTime : currentBreakTime);
  }, [mode, currentWorkTime, currentBreakTime]);

  const switchMode = useCallback((newMode: 'work' | 'break', autoTrigger = false) => {
    setMode(newMode);
    setIsActive(false);
    setTimeLeft(newMode === 'work' ? DURATIONS[preset].work : DURATIONS[preset].break);
    if (autoTrigger) {
      if (newMode === 'break') onComplete?.();
      setVisualAlert({ message: newMode === 'break' ? 'Foco Concluído!' : 'Intervalo encerrado!', type: newMode });
      setTimeout(() => setVisualAlert(null), 5000);
    }
  }, [preset, onComplete]);

  useEffect(() => {
    let interval: number | null = null;
    if (isActive && timeLeft > 0) {
      interval = window.setInterval(() => setTimeLeft((time) => time - 1), 1000);
    } else if (timeLeft === 0 && isActive) {
      switchMode(mode === 'work' ? 'break' : 'work', true);
    }
    return () => { if (interval) clearInterval(interval); };
  }, [isActive, timeLeft, mode, switchMode]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const progressPercent = (timeLeft / (mode === 'work' ? currentWorkTime : currentBreakTime)) * 100;
  const radius = 110;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - (progressPercent / 100) * circumference;

  if (isFocusMode) {
    return (
      <div className={`fixed inset-0 z-[200] flex flex-col items-center justify-center transition-colors duration-1000 ${mode === 'work' ? 'bg-slate-950 text-white' : 'bg-green-950 text-white'}`}>
        <button onClick={() => setIsFocusMode(false)} className="absolute top-8 right-8 p-3 rounded-full bg-white/10 text-white/60 hover:text-white"><Minimize2 className="w-6 h-6" /></button>
        <div className="mb-12 text-center z-10"><h2 className="text-sm font-bold uppercase tracking-[0.3em] text-white/40 mb-2">{mode === 'work' ? 'Foco Profundo' : 'Recuperação'}</h2><div className="h-1 w-12 bg-white/20 mx-auto rounded-full"></div></div>
        <div className="relative flex items-center justify-center w-80 h-80 sm:w-96 sm:h-96 mb-12 z-10">
          <svg className="w-full h-full -rotate-90 transform" viewBox="0 0 260 260">
            <circle className="text-white/5" strokeWidth="6" stroke="currentColor" fill="transparent" r={radius} cx="130" cy="130" />
            <circle className={`transition-all duration-1000 ease-linear ${mode === 'work' ? 'text-indigo-500 shadow-[0_0_20px_rgba(99,102,241,0.5)]' : 'text-green-500 shadow-[0_0_20px_rgba(34,197,94,0.5)]'}`} strokeWidth="8" strokeDasharray={circumference} style={{ strokeDashoffset }} strokeLinecap="round" stroke="currentColor" fill="transparent" r={radius} cx="130" cy="130" />
          </svg>
          <div className="absolute flex flex-col items-center justify-center"><span className="text-8xl sm:text-9xl font-black tabular-nums tracking-tighter">{formatTime(timeLeft)}</span></div>
        </div>
        <div className="flex gap-4 z-10"><Button onClick={toggleTimer} className={`w-48 py-5 rounded-full text-xl font-bold shadow-2xl ${isActive ? 'bg-white/10 text-white' : 'bg-indigo-600'}`}>{isActive ? <Pause /> : <Play />}</Button><Button onClick={resetTimer} className="w-16 h-16 rounded-full bg-white/5 text-white/60"><RotateCcw /></Button></div>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto text-center relative">
      {visualAlert && <div className="fixed top-24 left-1/2 -translate-x-1/2 z-50 animate-bounce"><div className={`px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 ${visualAlert.type === 'break' ? 'bg-green-600' : 'bg-indigo-600'} text-white`}><Bell /> <span className="font-bold">{visualAlert.message}</span></div></div>}
      <div className="mb-8 flex flex-col items-center"><h2 className="text-3xl font-bold mb-2">Timer de Foco</h2><p className="text-slate-600 mb-6">Mantenha a disciplina.</p><Button onClick={() => setIsFocusMode(true)} variant="secondary" className="rounded-full px-6 py-2 bg-indigo-50 text-indigo-600"><Maximize2 className="w-4 h-4 mr-2" /> Ativar Modo Foco</Button></div>
      <div className="flex items-center justify-center gap-4 mb-6"><div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl w-fit"><button onClick={() => setPreset('classic')} className={`px-4 py-2 rounded-lg text-sm font-bold ${preset === 'classic' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>25/5</button><button onClick={() => setPreset('sprint')} className={`px-4 py-2 rounded-lg text-sm font-bold ${preset === 'sprint' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}>50/10</button></div></div>
      <div className={`bg-white dark:bg-slate-900 rounded-3xl shadow-xl p-8 border-2 ${mode === 'work' ? 'border-slate-100' : 'border-green-100'}`}>
        <div className="relative flex items-center justify-center w-72 h-72 mb-6">
          <svg className="w-full h-full -rotate-90 transform" viewBox="0 0 260 260"><circle className="text-slate-100 dark:text-slate-800" strokeWidth="10" stroke="currentColor" fill="transparent" r={radius} cx="130" cy="130" /><circle className={`transition-all duration-1000 ease-linear ${mode === 'work' ? 'text-indigo-600' : 'text-green-600'}`} strokeWidth="12" strokeDasharray={circumference} style={{ strokeDashoffset }} strokeLinecap="round" stroke="currentColor" fill="transparent" r={radius} cx="130" cy="130" /></svg>
          <div className="absolute flex flex-col items-center justify-center"><span className={`text-6xl font-extrabold tabular-nums ${mode === 'work' ? 'text-slate-800 dark:text-slate-100' : 'text-green-600'}`}>{formatTime(timeLeft)}</span></div>
        </div>
        <div className="flex justify-center gap-4"><Button onClick={toggleTimer} className={`w-36 py-3.5 rounded-2xl text-lg ${isActive ? 'bg-slate-100 text-slate-800' : 'bg-indigo-600 text-white'}`}>{isActive ? 'Pausar' : 'Iniciar'}</Button><Button onClick={resetTimer} variant="secondary" className="px-5 py-3.5 rounded-2xl border-2"><RotateCcw /></Button></div>
      </div>
    </div>
  );
};

export default Timer;

import React, { useState, useEffect } from 'react';
import { ProcrastinationType, ActionPlan } from '../types';
import { generateActionPlan } from '../services/geminiService';
import Button from './Button';
import { Brain, CheckCircle, ArrowRight, RefreshCw, AlertCircle, Share2, Check, Target, BrainCircuit, Sparkles, Loader2, Wand2 } from 'lucide-react';

interface PlannerProps {
  title?: string;
  description?: string;
  onComplete?: () => void;
}

const Planner: React.FC<PlannerProps> = ({ 
  title = "Desbloqueio Mental", 
  description = "Identifique seu bloqueio para um plano de ação personalizado.",
  onComplete
}) => {
  const [task, setTask] = useState('');
  const [type, setType] = useState<ProcrastinationType>(ProcrastinationType.OVERWHELM);
  const [plan, setPlan] = useState<ActionPlan | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [copied, setCopied] = useState(false);
  const [loadingStep, setLoadingStep] = useState(0);

  const loadingMessages = [
    "Analisando seu bloqueio...",
    "Identificando padrões de comportamento...",
    "Consultando estratégias de foco...",
    "Quebrando tarefas em passos simples...",
    "Finalizando seu plano personalizado..."
  ];

  useEffect(() => {
    let interval: number;
    if (loading) {
      interval = window.setInterval(() => {
        setLoadingStep((prev) => (prev + 1) % loadingMessages.length);
      }, 1500);
    } else {
      setLoadingStep(0);
    }
    return () => clearInterval(interval);
  }, [loading]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const trimmedTask = task.trim();

    if (!trimmedTask || trimmedTask.length < 3) {
      setError("Por favor, descreva a tarefa (mínimo 3 caracteres).");
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const result = await generateActionPlan(trimmedTask, type);
      setPlan(result);
      onComplete?.();
    } catch (err) {
      setError("Não foi possível gerar o plano. Verifique sua conexão.");
    } finally {
      setLoading(false);
    }
  };

  const handleShare = async () => {
    if (!plan) return;
    const textToCopy = `🎯 *Plano de Ação: ${plan.title}*\n✨ "${plan.motivationalQuote}"\n\n*Passos:*\n${plan.steps.map((s, i) => `${i + 1}. ${s}`).join('\n')}`;
    try {
      await navigator.clipboard.writeText(textToCopy);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      alert("Erro ao copiar texto.");
    }
  };

  const reset = () => {
    setPlan(null);
    setTask('');
    setError(null);
  };

  if (loading) {
    return (
      <div className="max-w-2xl mx-auto py-20 flex flex-col items-center justify-center animate-fade-in bg-white dark:bg-slate-900 rounded-3xl shadow-2xl border border-indigo-50 dark:border-slate-800">
        <div className="relative mb-8">
          <div className="w-24 h-24 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-xl animate-pulse"><BrainCircuit className="w-12 h-12" /></div>
          <div className="absolute -inset-4 border-2 border-indigo-500/30 rounded-[2.5rem] animate-[ping_2s_infinite]"></div>
        </div>
        <div className="text-center space-y-3 px-8">
          <h3 className="text-xl font-bold text-slate-800 dark:text-white min-h-[1.5em] transition-all duration-300">{loadingMessages[loadingStep]}</h3>
          <div className="flex justify-center gap-1 pt-4">
            {loadingMessages.map((_, idx) => (
              <div key={idx} className={`h-1 rounded-full transition-all duration-500 ${idx === loadingStep ? 'w-6 bg-indigo-600' : 'w-1.5 bg-slate-200 dark:bg-slate-800'}`}></div>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (plan) {
    return (
      <div className="max-w-2xl mx-auto animate-fade-in">
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-2xl border border-indigo-50 dark:border-slate-800 overflow-hidden">
          <div className="bg-indigo-600 p-6 text-white text-center relative overflow-hidden">
            <h2 className="text-2xl font-bold mb-2 flex items-center justify-center gap-2"><Target className="w-6 h-6" /> {plan.title}</h2>
            <p className="opacity-90 italic text-sm">"{plan.motivationalQuote}"</p>
          </div>
          <div className="p-8">
            <div className="space-y-4">
              {plan.steps.map((step, idx) => (
                <div key={idx} className="flex gap-4 p-5 bg-slate-50 dark:bg-slate-800/40 rounded-2xl border border-slate-100 group transition-all">
                  <div className="flex-shrink-0 w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-bold text-sm">{idx + 1}</div>
                  <p className="text-slate-700 dark:text-slate-300 font-medium">{step}</p>
                </div>
              ))}
            </div>
            <div className="mt-8 pt-6 border-t border-slate-100 flex flex-wrap gap-4 justify-between items-center">
              <div className="flex gap-2 w-full">
                <Button onClick={handleShare} variant="secondary" className="flex-1">Compartilhar</Button>
                <Button onClick={reset} variant="secondary" className="flex-1">Novo Plano</Button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto animate-fade-in">
      <div className="text-center mb-10"><h2 className="text-3xl font-black mb-3">{title}</h2><p className="text-slate-600 dark:text-slate-400">{description}</p></div>
      <div className="bg-white dark:bg-slate-900 p-8 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-800">
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-sm font-bold mb-2">O que você está adiando?</label>
            <textarea value={task} onChange={(e) => setTask(e.target.value)} placeholder="Ex: Começar o relatório..." className="w-full px-4 py-4 rounded-2xl border border-slate-200 dark:bg-slate-800 outline-none resize-none h-32" />
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
            {Object.values(ProcrastinationType).map((t) => (
              <button key={t} type="button" onClick={() => setType(t)} className={`px-4 py-3 rounded-xl text-left text-sm font-medium border-2 ${type === t ? 'bg-indigo-50 border-indigo-600 text-indigo-700' : 'bg-white dark:bg-slate-800 border-slate-100'}`}>{t}</button>
            ))}
          </div>
          <Button type="submit" className="w-full py-4 text-lg font-bold" isLoading={loading}>Gerar Meu Desbloqueio</Button>
        </form>
      </div>
    </div>
  );
};

