  OVERWHELM = 'Sobrecarregado (Muitas tarefas)',
  PERFECTIONISM = 'Perfeccionismo (Padrões irreais)',
  BOREDOM = 'Tédio (Falta de interesse)',
  ANXIETY = 'Ansiedade (Medo do julgamento)',
  DISTRACTION = 'Distração (Ambiente ou digital)',
  FAILURE_FEAR = 'Medo do Fracasso (Evitação)',
  UNCLEAR = 'Falta de Clareza (Sem rumo)',
  FATIGUE = 'Canso (Físico ou Mental)',
  REBELLION = 'Resistência (Não quer fazer)'
}

