      icon: TimerIcon,
      color: "bg-rose-600",
      tips: ["Ative o 'Modo Foco' para uma experiência sem distrações."]
    },
    {
      title: "SOS Paralisia: O Resgate",
      description: "Travou completamente? O botão SOS é sua saída de emergência. A IA te dará um micro-desafio de 5 minutos para quebrar o ciclo de evitação.",
      icon: ShieldAlert,
      color: "bg-amber-600",
      tips: ["Não pense, apenas clique e faça o que for sugerido."]
    },
    {
      title: "Gamificação: Dopamina Saudável",
      description: "Tudo o que você faz no app gera XP. Suba de nível, mantenha seu streak e conquiste troféus. Produtividade agora é um jogo onde você sempre ganha.",
      icon: Trophy,
      color: "bg-emerald-600",
      tips: ["Concluir o Tutorial agora te dará +200 XP!"]
    }
  ];

  const handleNext = () => {
    if (currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1);
    } else {
      onComplete();
    }
  };

  const handlePrev = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
    }
  };

  const StepIcon = steps[currentStep].icon;

  return (
    <div className="max-w-3xl mx-auto min-h-[500px] flex flex-col items-center justify-center animate-fade-in px-4 py-8">
      {/* Progress Bar */}
      <div className="w-full h-1.5 bg-slate-200 dark:bg-slate-800 rounded-full mb-12 flex gap-1 overflow-hidden">
        {steps.map((_, i) => (
          <div 
            key={i} 
            className={`flex-1 h-full transition-all duration-500 ${i <= currentStep ? steps[currentStep].color : 'bg-transparent'}`}
          />
        ))}
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-[3rem] shadow-2xl border border-slate-100 dark:border-slate-800 w-full overflow-hidden flex flex-col md:flex-row">
        {/* Left Side: Visual */}
        <div className={`md:w-2/5 ${steps[currentStep].color} p-12 flex flex-col items-center justify-center text-white transition-colors duration-500`}>
          <div className="bg-white/20 p-6 rounded-[2rem] backdrop-blur-md mb-6 animate-bounce">
            <StepIcon className="w-16 h-16" />
          </div>
          <div className="text-center">
            <h4 className="font-black uppercase tracking-widest text-xs opacity-70 mb-2">Módulo {currentStep + 1}</h4>
            <div className="h-1 w-8 bg-white/40 mx-auto rounded-full"></div>
          </div>
        </div>

        {/* Right Side: Content */}
        <div className="md:w-3/5 p-8 md:p-12 flex flex-col">
          <div className="flex-1">
            <h2 className="text-3xl font-black text-slate-900 dark:text-white mb-4 leading-tight">
              {steps[currentStep].title}
            </h2>
            <p className="text-slate-600 dark:text-slate-400 text-lg leading-relaxed mb-8">
              {steps[currentStep].description}
            </p>

            <div className="space-y-3">
              {steps[currentStep].tips.map((tip, idx) => (
                <div key={idx} className="flex gap-3 items-start bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800/50">
                  <CheckCircle2 className="w-5 h-5 text-emerald-500 shrink-0 mt-0.5" />
                  <p className="text-sm font-medium text-slate-700 dark:text-slate-300">{tip}</p>
                </div>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-4 mt-12">
            {currentStep > 0 && (
              <Button variant="secondary" onClick={handlePrev} className="px-6 py-4 rounded-2xl">
                <ChevronLeft className="w-5 h-5 mr-1" /> Voltar
              </Button>
            )}
            <Button 
              onClick={handleNext} 
              className={`flex-1 py-4 rounded-2xl font-black text-lg ${steps[currentStep].color} hover:brightness-110 shadow-lg`}
            >
              {currentStep === steps.length - 1 ? 'VAMOS COMEÇAR!' : 'PRÓXIMO'} 
              {currentStep < steps.length - 1 && <ChevronRight className="ml-2 w-5 h-5" />}
            </Button>
          </div>
        </div>
      </div>

      <p className="mt-8 text-slate-400 text-xs font-medium flex items-center gap-2">
        <Target className="w-4 h-4" /> AntiPro v2.5 • Domine sua mente
      </p>
    </div>
  );
};

