import React, { useState, useEffect, useLayoutEffect } from 'react';
import { AppView, User } from './types';
import Planner from './components/Planner';
import Timer from './components/Timer';
import Coach from './components/Coach';
import ScrumBoard from './components/ScrumBoard';
import StatsView from './components/StatsView';
import EmergencyMode from './components/EmergencyMode';
import Tutorial from './components/Tutorial';
import LandingPage from './components/LandingPage';
import Button from './components/Button';
import CheckoutModal from './components/CheckoutModal';
import { getDailyInsight } from './services/geminiService';
import { 
  LayoutDashboard, 
  Timer as TimerIcon, 
  MessageCircle, 
  BrainCircuit, 
  Moon, 
  Sun, 
  Lock, 
  LogOut, 
  Star, 
  Layers, 
  Trophy, 
  Zap,
  BarChart3,
  ShieldAlert,
  Sparkles,
  HelpCircle
} from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
    if (typeof window === 'undefined') return null;
    const saved = localStorage.getItem('antipro_user');
    if (!saved) return null;
    const parsed = JSON.parse(saved);
    if (parsed.xp === undefined) {
      parsed.xp = 0;
      parsed.level = 1;
      parsed.streak = 0;
    }
    return parsed;
  });

  const [isDarkMode, setIsDarkMode] = useState(() => {
    if (typeof window === 'undefined') return false;
    const saved = localStorage.getItem('theme');
    if (saved) return saved === 'dark';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  const [isInitialized, setIsInitialized] = useState(false);
  const [currentView, setCurrentView] = useState<AppView>(AppView.DASHBOARD);
  const [selectedPlan, setSelectedPlan] = useState<{name: string, price: string} | null>(null);
  const [showLevelUp, setShowLevelUp] = useState(false);
  const [showEmergency, setShowEmergency] = useState(false);
  const [dailyInsight, setDailyInsight] = useState<string>('Carregando seu insight matinal...');

  useLayoutEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      localStorage.setItem('theme', 'dark');
    } else {
      document.documentElement.classList.remove('dark');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  useEffect(() => {
    const timer = setTimeout(() => {
      setIsInitialized(true);
    }, 400);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    if (user && currentView === AppView.DASHBOARD) {
      const tasks = localStorage.getItem('antipro_scrum_tasks') || '[]';
      getDailyInsight(tasks).then(setDailyInsight);
    }
  }, [currentView, user]);

  const saveUser = (updatedUser: User) => {
    setUser(updatedUser);
    localStorage.setItem('antipro_user', JSON.stringify(updatedUser));
  };

  const addXP = (amount: number) => {
    if (!user) return;
    let newXP = user.xp + amount;
    let newLevel = user.level;
    const xpToNextLevel = user.level * 1000;

    if (newXP >= xpToNextLevel) {
      newXP -= xpToNextLevel;
      newLevel += 1;
      setShowLevelUp(true);
      setTimeout(() => setShowLevelUp(false), 5000);
    }

    saveUser({ ...user, xp: newXP, level: newLevel });
  };

  const toggleDarkMode = () => setIsDarkMode(!isDarkMode);

  const handleRegister = (userData: { name: string; email: string; phone: string }) => {
    const newUser: User = { 
      ...userData, 
      createdAt: Date.now(), 
      isSubscribed: false,
      xp: 0,
      level: 1,
      streak: 1,
      lastActive: Date.now()
    };
    saveUser(newUser);
    // Sugerir tutorial para novos usuários
    setCurrentView(AppView.TUTORIAL);
  };

  const handleLogout = () => {
    localStorage.removeItem('antipro_user');
    setUser(null);
    setCurrentView(AppView.DASHBOARD);
  };

  const handleInitiateCheckout = (planName: string, price: string) => {
    setSelectedPlan({ name: planName, price });
  };

  const handleCompleteSubscription = () => {
    if (user) {
      saveUser({ ...user, isSubscribed: true });
      setSelectedPlan(null);
      setCurrentView(AppView.DASHBOARD);
    }
  };

  const isTrialExpired = () => {
    if (!user) return false;
    if (user.isSubscribed) return false;
    const threeDaysInMs = 3 * 24 * 60 * 60 * 1000;
    return (Date.now() - user.createdAt) > threeDaysInMs;
  };

  const getViewStyles = (view: AppView) => {
    switch (view) {
      case AppView.PLANNER:
        return { active: 'bg-purple-50 text-purple-700 border-purple-600 dark:bg-purple-900/20 dark:text-purple-400 dark:border-purple-500', icon: BrainCircuit, label: 'Plano' };
      case AppView.TIMER:
        return { active: 'bg-red-50 text-red-700 border-red-600 dark:bg-red-900/20 dark:text-red-400 dark:border-red-500', icon: TimerIcon, label: 'Foco' };
      case AppView.COACH:
        return { active: 'bg-blue-50 text-blue-700 border-blue-600 dark:bg-blue-900/20 dark:text-blue-400 dark:border-blue-500', icon: MessageCircle, label: 'Coach' };
      case AppView.SCRUM:
        return { active: 'bg-indigo-50 text-indigo-700 border-indigo-600 dark:bg-indigo-900/20 dark:text-indigo-400 dark:border-indigo-500', icon: Layers, label: 'Board' };
      case AppView.STATS:
        return { active: 'bg-emerald-50 text-emerald-700 border-emerald-600 dark:bg-emerald-900/20 dark:text-emerald-400 dark:border-emerald-500', icon: BarChart3, label: 'Stats' };
      case AppView.DASHBOARD:
      default:
        return { active: 'bg-slate-50 text-slate-700 border-slate-600 dark:bg-slate-900/20 dark:text-slate-400 dark:border-slate-500', icon: LayoutDashboard, label: 'Início' };
    }
  };

  const NavButton = ({ view }: { view: AppView }) => {
    const styles = getViewStyles(view);
    const Icon = styles.icon;
    const isActive = currentView === view;
    return (
      <button
        onClick={() => setCurrentView(view)}
        className={`flex flex-col items-center justify-center px-3 py-2 rounded-xl transition-all duration-300 w-full sm:w-auto border-2 ${
          isActive
            ? `${styles.active} shadow-lg scale-105 font-bold`
            : `bg-white dark:bg-slate-900 border-transparent text-slate-500 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800`
        }`}
      >
        <Icon className={`w-5 h-5 mb-1 ${isActive ? 'stroke-2' : 'stroke-1.5'}`} />
        <span className="text-[9px] uppercase font-bold tracking-tighter">{styles.label}</span>
      </button>
    );
  };

  if (!isInitialized) return null;

  if (!user) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-950 animate-fade-in">
        <header className="max-w-6xl mx-auto px-4 h-20 flex items-center justify-between">
           <div className="flex items-center gap-3 font-bold text-xl text-slate-900 dark:text-slate-100">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><BrainCircuit className="w-6 h-6" /></div>
            <span>AntiPro</span>
          </div>
          <button onClick={toggleDarkMode} className="p-2.5 rounded-xl bg-white dark:bg-slate-900 shadow-sm border border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-400">
            {isDarkMode ? <Sun className="w-5 h-5" /> : <Moon className="w-5 h-5" />}
          </button>
        </header>
        <LandingPage onRegister={handleRegister} onDirectSubscribe={handleInitiateCheckout} />
        {selectedPlan && (
          <CheckoutModal planName={selectedPlan.name} price={selectedPlan.price} onConfirm={handleCompleteSubscription} onCancel={() => setSelectedPlan(null)} />
        )}
      </div>
    );
  }

  const renderContent = () => {
    if (isTrialExpired()) return <div className="text-center py-20"><Lock className="w-20 h-20 mx-auto text-red-500 mb-4" /><h2 className="text-3xl font-black">Trial Expirado</h2><p>Assine para continuar.</p></div>;

    switch (currentView) {
      case AppView.PLANNER: return <Planner onComplete={() => addXP(150)} />;
      case AppView.TIMER: return <Timer onComplete={() => addXP(200)} />;
      case AppView.COACH: return <Coach />;
      case AppView.SCRUM: return <ScrumBoard onTaskDone={() => addXP(100)} />;
      case AppView.STATS: return <StatsView />;
      case AppView.TUTORIAL: return <Tutorial onComplete={() => { addXP(200); setCurrentView(AppView.DASHBOARD); }} />;
      case AppView.DASHBOARD:
      default:
        return (
          <div className="max-w-4xl mx-auto animate-fade-in space-y-8">
            {/* IA Standup Section */}
            <div className="bg-white dark:bg-slate-900 p-6 rounded-[2.5rem] border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col md:flex-row items-center gap-6">
               <div className="w-20 h-20 bg-indigo-100 dark:bg-indigo-900/30 rounded-3xl flex items-center justify-center text-indigo-600 flex-shrink-0 animate-pulse">
                  <Sparkles className="w-10 h-10" />
               </div>
               <div className="text-center md:text-left flex-1">
                  <h3 className="text-xs font-black uppercase text-indigo-600 mb-1 tracking-widest">IA Insight Diário</h3>
                  <p className="text-slate-700 dark:text-slate-300 font-medium text-lg leading-tight">"{dailyInsight}"</p>
               </div>
               <div className="flex flex-col sm:flex-row gap-2 shrink-0">
                 <Button onClick={() => setShowEmergency(true)} className="bg-rose-500 hover:bg-rose-600 text-white rounded-2xl px-6 py-4 flex items-center gap-2 group">
                    <ShieldAlert className="w-5 h-5 group-hover:animate-shake" /> SOS Paralisia
                 </Button>
                 <Button onClick={() => setCurrentView(AppView.TUTORIAL)} variant="secondary" className="rounded-2xl px-6 py-4 flex items-center gap-2">
                    <HelpCircle className="w-5 h-5" /> Guia
                 </Button>
               </div>
            </div>

            <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
              <div className="bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex items-center gap-4">
                 <div className="w-12 h-12 bg-amber-100 dark:bg-amber-900/30 rounded-2xl flex items-center justify-center text-amber-600"><Trophy className="w-6 h-6" /></div>
                 <div><p className="text-[10px] font-bold text-slate-400 uppercase">Nível</p><p className="text-xl font-black">{user.level}</p></div>
              </div>
              <div className="bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex items-center gap-4">
                 <div className="w-12 h-12 bg-indigo-100 dark:bg-indigo-900/30 rounded-2xl flex items-center justify-center text-indigo-600"><Zap className="w-6 h-6" /></div>
                 <div><p className="text-[10px] font-bold text-slate-400 uppercase">XP</p><p className="text-xl font-black">{user.xp}</p></div>
              </div>
              <div className="col-span-2 sm:col-span-1 bg-white dark:bg-slate-900 p-5 rounded-3xl border border-slate-200 dark:border-slate-800 shadow-sm flex items-center gap-4">
                 <div className="w-12 h-12 bg-rose-100 dark:bg-rose-900/30 rounded-2xl flex items-center justify-center text-rose-600"><Star className="w-6 h-6" /></div>
                 <div><p className="text-[10px] font-bold text-slate-400 uppercase">Streak</p><p className="text-xl font-black">{user.streak}d</p></div>
              </div>
            </div>

            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
               {[
                 { v: AppView.SCRUM, i: Layers, c: 'indigo', l: 'Scrum Board', d: 'Seu ciclo ágil.' },
                 { v: AppView.PLANNER, i: BrainCircuit, c: 'purple', l: 'IA Planner', d: 'Planos de ação.' },
                 { v: AppView.TIMER, i: TimerIcon, c: 'red', l: 'Foco Pomodoro', d: 'Alta concentração.' },
                 { v: AppView.COACH, i: MessageCircle, c: 'blue', l: 'Coach IA', d: 'Converse agora.' },
                 { v: AppView.STATS, i: BarChart3, c: 'emerald', l: 'Analytics', d: 'Veja seus padrões.' }
               ].map(item => (
                 <div key={item.v} onClick={() => setCurrentView(item.v)} className="bg-white dark:bg-slate-900 p-6 rounded-3xl shadow-sm border-2 border-slate-100 dark:border-slate-800 hover:border-indigo-300 hover:shadow-xl transition-all cursor-pointer group">
                   <div className={`w-12 h-12 rounded-2xl flex items-center justify-center mb-4 bg-${item.c}-100 dark:bg-${item.c}-900/30 text-${item.c}-600 group-hover:scale-110 transition-transform`}><item.i className="w-6 h-6" /></div>
                   <h3 className="text-lg font-bold mb-1">{item.l}</h3>
                   <p className="text-slate-500 text-xs">{item.d}</p>
                 </div>
               ))}
            </div>
          </div>
        );
    }
  };

  const xpProgress = (user.xp / (user.level * 1000)) * 100;

  return (
    <div className="min-h-screen flex flex-col bg-slate-50 dark:bg-slate-950 transition-colors duration-300">
      <header className="bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 sticky top-0 z-50 shadow-sm">
        <div className="max-w-6xl mx-auto px-4 h-20 flex items-center justify-between gap-4">
          <div className="flex items-center gap-3 cursor-pointer font-bold text-xl text-slate-900 dark:text-slate-100 shrink-0" onClick={() => setCurrentView(AppView.DASHBOARD)}>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><BrainCircuit className="w-6 h-6" /></div>
            <span className="hidden sm:inline">AntiPro</span>
          </div>
          <div className="flex-1 max-w-xs hidden md:block">
            <div className="flex justify-between text-[10px] font-bold uppercase text-slate-400 mb-1"><span>Nível {user.level}</span><span>{Math.round(xpProgress)}%</span></div>
            <div className="h-2 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden"><div className="h-full bg-indigo-600 transition-all duration-500" style={{ width: `${xpProgress}%` }}></div></div>
          </div>
          <div className="flex items-center gap-1 md:gap-2">
            <div className="hidden lg:flex gap-1">
              <NavButton view={AppView.DASHBOARD} /><NavButton view={AppView.SCRUM} /><NavButton view={AppView.PLANNER} /><NavButton view={AppView.TIMER} /><NavButton view={AppView.COACH} /><NavButton view={AppView.STATS} />
            </div>
            <div className="flex gap-1">
              <button onClick={toggleDarkMode} className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 transition-colors"><Sun className="w-5 h-5" /></button>
              <button onClick={handleLogout} className="p-2.5 rounded-xl bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 hover:bg-red-100 transition-colors"><LogOut className="w-5 h-5" /></button>
            </div>
          </div>
        </div>
      </header>

      {showLevelUp && <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[200] animate-bounce"><div className="bg-indigo-600 text-white px-8 py-4 rounded-3xl shadow-2xl flex items-center gap-4 border-4 border-indigo-400"><Trophy className="w-10 h-10 text-yellow-300" /><div><p className="text-xs font-black uppercase">Parabéns!</p><h4 className="text-xl font-black">Nível {user.level}!</h4></div></div></div>}
      {showEmergency && <EmergencyMode onClose={() => setShowEmergency(false)} onSuccess={() => addXP(500)} />}

      <div className="lg:hidden fixed bottom-0 left-0 right-0 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 p-2 flex justify-around z-50 shadow-lg">
        <NavButton view={AppView.DASHBOARD} /><NavButton view={AppView.SCRUM} /><NavButton view={AppView.STATS} /><NavButton view={AppView.TIMER} /><NavButton view={AppView.COACH} />
      </div>

      <main className="flex-1 p-4 md:p-8 pb-32 lg:pb-8 max-w-6xl mx-auto w-full">{renderContent()}</main>
    </div>
  );
};

